import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus, DisputeCategory } from '../types';
import { getRequestsForUser, uploadVideo, openDispute } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, AlertTriangle, Video, Wallet, 
  ShieldCheck, Camera, Info, X, TrendingUp, 
  Package, Clock, Star, AlertCircle, RefreshCw
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedRequest, setSelectedRequest] = useState<VideoRequest | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Quality Check State
  const [qualityCheck, setQualityCheck] = useState({ nameSaid: false, durationOk: false, audioClear: false });
  const [videoFile, setVideoFile] = useState<File | null>(null);

  // Dispute State
  const [disputeModal, setDisputeModal] = useState<VideoRequest | null>(null);
  const [disputeCategory, setDisputeCategory] = useState<DisputeCategory>('TECH_ISSUE');
  const [disputeReason, setDisputeReason] = useState('');

  const refresh = async () => {
    setLoading(true);
    setError(null);
    try {
        const data = await getRequestsForUser(user.id, user.role);
        setRequests(data);
    } catch (err: any) {
        console.error("Dashboard Fetch Error:", err);
        setError("Errore nel caricamento degli ordini. Assicurati che gli indici Firestore siano configurati o riprova più tardi.");
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleUpload = async () => {
    if (!selectedRequest || !videoFile) return;
    setIsSubmitting(true);
    try {
        await uploadVideo(videoFile, selectedRequest.id, qualityCheck);
        setSelectedRequest(null);
        refresh();
    } catch (e) {
        alert("Errore caricamento.");
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleSubmitDispute = async () => {
      if (!disputeModal || !disputeReason) return;
      await openDispute(disputeModal.id, disputeCategory, disputeReason);
      setDisputeModal(null);
      refresh();
  };

  // KPI Calculation
  const stats = {
      total: requests.length,
      completed: requests.filter(r => r.status === RequestStatus.COMPLETED).length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      earnings: requests.filter(r => r.status === RequestStatus.COMPLETED).reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="animate-spin w-12 h-12 text-slate-900 mb-4" />
        <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Sincronizzazione dati in corso...</p>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">

      {/* Header & Welcome */}
      <div className="flex flex-col md:flex-row md:items-end justify-between mb-10 gap-6">
          <div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tighter mb-2">
                Bentornato, {user.name.split(' ')[0]}
              </h1>
              <p className="text-slate-500 font-medium">
                {user.role === UserRole.TALENT ? 'Gestisci le tue richieste e monitora i tuoi guadagni.' : 'Guarda i tuoi video e lo stato dei tuoi ordini.'}
              </p>
          </div>
          <button 
            onClick={refresh}
            className="flex items-center gap-2 bg-white border border-slate-200 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all text-slate-600"
          >
            <RefreshCw className="w-3.5 h-3.5" /> Aggiorna
          </button>
      </div>

      {error && (
          <div className="mb-8 bg-red-50 border border-red-100 p-6 rounded-[32px] flex items-start gap-4 animate-in fade-in slide-in-from-top-4">
              <AlertCircle className="w-6 h-6 text-red-600 mt-1 flex-shrink-0" />
              <div>
                  <h4 className="text-red-900 font-black uppercase text-xs mb-1">Errore di Sincronizzazione</h4>
                  <p className="text-red-700 text-sm font-medium">{error}</p>
              </div>
          </div>
      )}

      {/* KPI Cards Section */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4">
              <div className="bg-slate-900 p-3 rounded-2xl text-white">
                  <Package className="w-5 h-5" />
              </div>
              <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ordini Totali</p>
                  <p className="text-2xl font-black text-slate-900">{stats.total}</p>
              </div>
          </div>
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4">
              <div className="bg-amber-100 p-3 rounded-2xl text-amber-600">
                  <Clock className="w-5 h-5" />
              </div>
              <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">In Attesa</p>
                  <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
              </div>
          </div>
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4">
              <div className="bg-emerald-100 p-3 rounded-2xl text-emerald-600">
                  <CheckCircle className="w-5 h-5" />
              </div>
              <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Completati</p>
                  <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
              </div>
          </div>
          {user.role === UserRole.TALENT ? (
              <div className="bg-slate-900 p-6 rounded-[32px] text-white shadow-xl shadow-slate-900/10 flex items-center gap-4">
                  <div className="bg-white/10 p-3 rounded-2xl">
                      <TrendingUp className="w-5 h-5 text-emerald-400" />
                  </div>
                  <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Guadagni Netti</p>
                      <p className="text-2xl font-black">€{stats.earnings.toFixed(2)}</p>
                  </div>
              </div>
          ) : (
              <div className="bg-blue-600 p-6 rounded-[32px] text-white shadow-xl shadow-blue-600/10 flex items-center gap-4">
                  <div className="bg-white/10 p-3 rounded-2xl">
                      <Star className="w-5 h-5 text-white" />
                  </div>
                  <div>
                      <p className="text-[10px] font-black text-white/60 uppercase tracking-widest">Fedeltà Fan</p>
                      <p className="text-2xl font-black">Pro</p>
                  </div>
              </div>
          )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">

          {/* Main Feed */}
          <div className="lg:col-span-8 space-y-8">
              {requests.length === 0 && !error ? (
                  <div className="p-20 text-center bg-white rounded-[40px] border-2 border-dashed border-slate-100 flex flex-col items-center">
                      <div className="bg-slate-50 p-6 rounded-full mb-6">
                        <Video className="w-12 h-12 text-slate-200" />
                      </div>
                      <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter mb-2">Nessun ordine trovato</h3>
                      <p className="text-slate-500 text-sm max-w-xs mx-auto mb-8 font-medium">Non hai ancora effettuato o ricevuto ordini. Inizia subito a esplorare!</p>
                      {user.role === UserRole.FAN && (
                          <button onClick={() => window.location.href = '#/'} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg hover:bg-black transition-all">Sfoglia Talenti</button>
                      )}
                  </div>
              ) : (
                  requests.map(req => (
                      <div key={req.id} className="bg-white rounded-[32px] p-8 border border-slate-100 shadow-[0_8px_30px_rgb(0,0,0,0.02)] transition-all hover:shadow-[0_8px_30px_rgb(0,0,0,0.05)]">
                          <div className="flex flex-col md:flex-row gap-8">
                              <div className="flex-1">
                                  <div className="flex justify-between items-start mb-6">
                                      <div>
                                          <div className="flex items-center gap-3 mb-1">
                                            <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase tracking-widest">Ordine #{req.id.substring(0,8)}</span>
                                            <span className={`text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest border ${
                                                req.status === RequestStatus.COMPLETED ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                                                req.status === RequestStatus.DISPUTE_OPEN ? 'bg-red-50 text-red-600 border-red-100' :
                                                req.status === RequestStatus.PENDING ? 'bg-amber-50 text-amber-600 border-amber-100' :
                                                'bg-slate-50 text-slate-500 border-slate-100'
                                            }`}>
                                                {req.status}
                                            </span>
                                          </div>
                                          <p className="font-black text-2xl text-slate-900 tracking-tighter">
                                              {user.role === UserRole.FAN ? `Per: ${req.recipientName}` : `Da: ${req.fanName}`}
                                          </p>
                                      </div>
                                      <div className="text-right">
                                          <p className="text-2xl font-black text-slate-900">€{req.pricePaid}</p>
                                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{new Date(req.createdAt).toLocaleDateString()}</p>
                                      </div>
                                  </div>

                                  <div className="bg-slate-50 rounded-2xl p-5 mb-6 border border-slate-100 relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-300"></div>
                                      <p className="text-[10px] font-black text-slate-400 uppercase mb-2 tracking-widest">Istruzioni Ricevute</p>
                                      <p className="text-sm italic text-slate-700 leading-relaxed font-medium">"{req.instructions}"</p>
                                  </div>

                                  {req.videoUrl && (
                                      <div className="mt-8 pt-8 border-t border-slate-50">
                                          <VideoPlayer src={req.videoUrl} />
                                          {user.role === UserRole.FAN && req.status === RequestStatus.IN_REVIEW && (
                                              <div className="flex gap-4 mt-6">
                                                  <button className="flex-1 bg-emerald-600 text-white py-4 rounded-[20px] font-black text-xs uppercase shadow-lg hover:bg-emerald-700 transition-all flex items-center justify-center gap-2">
                                                      <CheckCircle className="w-4 h-4" /> Accetta Video
                                                  </button>
                                                  <button onClick={() => setDisputeModal(req)} className="flex-1 border-2 border-slate-100 text-slate-400 hover:text-red-600 hover:border-red-100 py-4 rounded-[20px] font-black text-xs uppercase transition-all">
                                                      Segnala Problema
                                                  </button>
                                              </div>
                                          )}
                                      </div>
                                  )}
                              </div>

                              {user.role === UserRole.TALENT && req.status === RequestStatus.PENDING && (
                                  <div className="md:w-56 flex flex-col justify-center">
                                      <button 
                                          onClick={() => setSelectedRequest(req)}
                                          className="w-full bg-slate-900 text-white py-5 rounded-[24px] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-black transition-all transform hover:-translate-y-1"
                                      >
                                          CONSEGNA ORA
                                      </button>
                                      <p className="text-[9px] text-center mt-4 text-slate-400 font-bold uppercase tracking-widest px-4">
                                          Scade il {new Date(req.expirationTimestamp).toLocaleDateString()}
                                      </p>
                                  </div>
                              )}
                          </div>
                      </div>
                  ))
              )}
          </div>

          {/* Sidebar Info */}
          <div className="lg:col-span-4 space-y-8">
              <div className="bg-slate-900 rounded-[32px] p-8 text-white shadow-2xl relative overflow-hidden group">
                  <div className="absolute -top-10 -right-10 w-40 h-40 bg-white/5 rounded-full blur-3xl group-hover:scale-150 transition-transform duration-700"></div>
                  <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6 flex items-center gap-2">
                      <Wallet className="w-4 h-4 text-emerald-400" /> CiaoStar Wallet
                  </h3>
                  <div className="mb-8">
                      <p className="text-4xl font-black tracking-tighter mb-1">€{stats.earnings.toFixed(2)}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Saldo disponibile pre-prelievo</p>
                  </div>
                  <button className="w-full bg-white text-slate-900 py-4 rounded-2xl font-black text-[10px] hover:bg-slate-100 transition-all uppercase tracking-widest flex items-center justify-center gap-2">
                      <RefreshCw className="w-3.5 h-3.5" /> Gestisci Stripe
                  </button>
              </div>

              <div className="bg-white border border-slate-100 rounded-[32px] p-8 shadow-sm">
                  <h3 className="text-[10px] font-black uppercase tracking-widest mb-6 flex items-center gap-2 text-slate-400">
                      <Info className="w-4 h-4 text-blue-500" /> Linee Guida Qualità
                  </h3>
                  <ul className="space-y-5">
                      <li className="flex items-start gap-4">
                          <div className="w-8 h-8 rounded-xl bg-emerald-50 text-emerald-600 flex items-center justify-center flex-shrink-0">
                              <Star className="w-4 h-4 fill-current" />
                          </div>
                          <div>
                              <p className="text-[10px] font-black text-slate-900 uppercase">Nomi Chiarissimi</p>
                              <p className="text-xs text-slate-500 font-medium leading-relaxed">Assicurati che il nome del destinatario sia udibile perfettamente.</p>
                          </div>
                      </li>
                      <li className="flex items-start gap-4">
                          <div className="w-8 h-8 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0">
                              <Clock className="w-4 h-4" />
                          </div>
                          <div>
                              <p className="text-[10px] font-black text-slate-900 uppercase">Durata minima</p>
                              <p className="text-xs text-slate-500 font-medium leading-relaxed">Il video deve durare almeno 20 secondi per essere valido.</p>
                          </div>
                      </li>
                      <li className="flex items-start gap-4">
                          <div className="w-8 h-8 rounded-xl bg-amber-50 text-amber-600 flex items-center justify-center flex-shrink-0">
                              <ShieldCheck className="w-4 h-4" />
                          </div>
                          <div>
                              <p className="text-[10px] font-black text-slate-900 uppercase">Contesto Ok</p>
                              <p className="text-xs text-slate-500 font-medium leading-relaxed">Usa una buona illuminazione e riduci i rumori di fondo.</p>
                          </div>
                      </li>
                  </ul>
              </div>
          </div>
      </div>

      {/* VIP QUALITY MODAL */}
      {selectedRequest && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in">
              <div className="bg-white rounded-[40px] max-w-xl w-full p-10 shadow-2xl overflow-y-auto max-h-[90vh] border border-white/20">
                  <div className="flex justify-between items-center mb-8">
                      <div className="bg-slate-100 px-4 py-1.5 rounded-xl">
                          <h2 className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Consegna Ufficiale Video</h2>
                      </div>
                      <button onClick={() => setSelectedRequest(null)} className="p-2 hover:bg-slate-50 rounded-full transition-all text-slate-400 hover:text-slate-900"><X className="w-6 h-6"/></button>
                  </div>

                  <div className="bg-slate-50 border border-slate-100 rounded-[28px] p-6 mb-8 relative">
                      <div className="absolute -top-3 left-6 bg-white border border-slate-100 px-3 py-1 rounded-lg text-[9px] font-black uppercase text-slate-400">Reminder Istruzioni</div>
                      <p className="text-sm font-black text-slate-900 mb-1">Destinatario: {selectedRequest.recipientName}</p>
                      <p className="text-sm italic text-slate-500 leading-relaxed font-medium">"{selectedRequest.instructions}"</p>
                  </div>

                  <div className="space-y-4 mb-8">
                      <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 ml-1">Checklist di Conformità</h3>
                      {[
                          { key: 'nameSaid', label: `Ho detto il nome "${selectedRequest.recipientName}"?` },
                          { key: 'durationOk', label: "Il video dura almeno 20 secondi?" },
                          { key: 'audioClear', label: "L'audio è chiaro e professionale?" }
                      ].map(item => (
                          <label key={item.key} className="group flex items-center gap-4 cursor-pointer p-4 rounded-2xl border border-slate-50 hover:bg-slate-50 hover:border-slate-200 transition-all">
                              <div className="relative">
                                <input 
                                    type="checkbox" 
                                    checked={(qualityCheck as any)[item.key]}
                                    onChange={e => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                    className="peer sr-only"
                                />
                                <div className="w-6 h-6 border-2 border-slate-200 rounded-lg peer-checked:bg-slate-900 peer-checked:border-slate-900 transition-all flex items-center justify-center">
                                  <CheckCircle className="w-3.5 h-3.5 text-white opacity-0 peer-checked:opacity-100" />
                                </div>
                              </div>
                              <span className="font-bold text-slate-700 text-sm">{item.label}</span>
                          </label>
                      ))}
                  </div>

                  <div className="mb-10">
                      <label className="block border-2 border-dashed border-slate-100 bg-slate-50/50 rounded-[32px] p-12 text-center cursor-pointer hover:border-slate-300 hover:bg-slate-50 transition-all group">
                          <input type="file" accept="video/*" capture="user" className="hidden" onChange={e => setVideoFile(e.target.files?.[0] || null)} />
                          {videoFile ? (
                              <div className="flex flex-col items-center">
                                  <div className="bg-emerald-100 p-4 rounded-full mb-4">
                                    <Video className="w-10 h-10 text-emerald-600" />
                                  </div>
                                  <span className="font-black text-sm text-slate-900 uppercase tracking-tighter">{videoFile.name}</span>
                                  <span className="text-[9px] font-black text-emerald-500 uppercase mt-1 tracking-widest">Pronto per l'invio</span>
                              </div>
                          ) : (
                              <div className="flex flex-col items-center">
                                  <div className="bg-white p-4 rounded-full shadow-sm mb-4 group-hover:scale-110 transition-transform">
                                    <Camera className="w-10 h-10 text-slate-300" />
                                  </div>
                                  <span className="font-black text-slate-900 uppercase text-xs tracking-widest">Seleziona o Registra Video</span>
                                  <span className="text-[9px] font-bold text-slate-400 uppercase mt-2">Formati MP4, MOV, WEBM</span>
                              </div>
                          )}
                      </label>
                  </div>

                  <button 
                      disabled={!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear || !videoFile || isSubmitting}
                      onClick={handleUpload}
                      className="w-full bg-slate-900 text-white py-6 rounded-[28px] font-black text-lg uppercase tracking-tight shadow-2xl hover:bg-black transition-all disabled:opacity-20 disabled:grayscale disabled:scale-100 flex items-center justify-center gap-3 transform hover:-translate-y-1"
                  >
                      {isSubmitting ? <Loader2 className="animate-spin" /> : <><Video className="w-5 h-5 text-amber-400" /> CONFERMA E INVIA</>}
                  </button>
              </div>
          </div>
      )}

      {/* DISPUTE MODAL (FAN) */}
      {disputeModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in">
              <div className="bg-white rounded-[40px] max-w-lg w-full p-10 shadow-2xl border border-white/20">
                  <div className="flex justify-between items-center mb-8">
                      <div className="bg-red-50 px-4 py-1.5 rounded-xl">
                        <h2 className="text-[10px] font-black text-red-600 uppercase tracking-widest">Protezione Fan & Supporto</h2>
                      </div>
                      <button onClick={() => setDisputeModal(null)} className="p-2 hover:bg-slate-50 rounded-full text-slate-400 hover:text-slate-900"><X className="w-6 h-6"/></button>
                  </div>

                  <div className="bg-red-50 p-6 rounded-[28px] mb-8 flex items-start gap-4 border border-red-100">
                      <AlertTriangle className="w-6 h-6 text-red-600 mt-0.5 flex-shrink-0" />
                      <div>
                          <p className="text-xs text-red-800 leading-relaxed font-bold">
                              Il rimborso è garantito per motivi oggettivi: audio/video pessimo, nome sbagliato, durata inferiore ai 20 secondi. 
                          </p>
                          <p className="text-[9px] text-red-500 font-bold uppercase mt-2 tracking-widest">L'Admin valuterà entro 24h.</p>
                      </div>
                  </div>

                  <div className="space-y-6 mb-10">
                      <div>
                        <label className="block text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest ml-1">Categoria Problema</label>
                        <select 
                            value={disputeCategory}
                            onChange={e => setDisputeCategory(e.target.value as DisputeCategory)}
                            className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 font-black text-sm outline-none focus:ring-2 focus:ring-red-500/20 appearance-none cursor-pointer"
                        >
                            <option value="TECH_ISSUE">Problemi Tecnici (Audio/Video)</option>
                            <option value="CONTENT_ERROR">Errore Nome o Istruzioni</option>
                            <option value="DURATION">Video troppo breve (&lt; 20s)</option>
                            <option value="OTHER">Altro (specifica sotto)</option>
                        </select>
                      </div>

                      <div>
                        <label className="block text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest ml-1">Spiegazione Dettagliata</label>
                        <textarea 
                            className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 font-medium text-sm min-h-[120px] outline-none focus:ring-2 focus:ring-red-500/20 resize-none leading-relaxed"
                            placeholder="Raccontaci cosa non va nel video..."
                            value={disputeReason}
                            onChange={e => setDisputeReason(e.target.value)}
                        />
                      </div>
                  </div>

                  <button 
                      onClick={handleSubmitDispute}
                      disabled={!disputeReason}
                      className="w-full bg-red-600 text-white py-5 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-xl hover:bg-red-700 disabled:opacity-20 transition-all flex items-center justify-center gap-2"
                  >
                      <AlertTriangle className="w-4 h-4" /> APRI DISPUTA UFFICIALE
                  </button>
                  <p className="text-center text-[9px] font-black text-slate-300 uppercase mt-6 tracking-[0.2em]">Procedura protetta da Garanzia CiaoStar</p>
              </div>
          </div>
      )}
    </div>
  );
};

export default Dashboard;

import { db, storage, auth } from '../firebaseConfig';
import { 
  collection, addDoc, getDocs, query, where, updateDoc, doc, getDoc, setDoc, 
  orderBy, limit, serverTimestamp, increment, onSnapshot, deleteDoc
} from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { Talent, User, UserRole, VideoRequest, RequestStatus, AdminSettings, AuditLog, ChatMessage, Conversation, VerificationStatus, DisputeCategory } from '../types';
import { ADMIN_EMAIL, DEFAULT_ADMIN_SETTINGS, DB_CATEGORIES_SEED } from '../constants';

// --- SETTINGS ---

export const getAdminSettings = async (): Promise<AdminSettings> => {
    const settingsRef = doc(db, 'settings', 'global_config');
    const snap = await getDoc(settingsRef);
    if (snap.exists()) return snap.data() as AdminSettings;
    await setDoc(settingsRef, { ...DEFAULT_ADMIN_SETTINGS });
    return DEFAULT_ADMIN_SETTINGS;
