const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const navigate = useNavigate();
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedRequest, setSelectedRequest] = useState<VideoRequest | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Talent Upload State
  const [qualityCheck, setQualityCheck] = useState({ nameSaid: false, durationOk: false, audioClear: false });
  const [videoFile, setVideoFile] = useState<File | null>(null);

  // Fan Dispute State
  const [disputeModal, setDisputeModal] = useState<VideoRequest | null>(null);
  const [disputeCategory, setDisputeCategory] = useState<DisputeCategory>('TECH_ISSUE');
  const [disputeReason, setDisputeReason] = useState('');

  const refresh = async () => {
    setLoading(true);
    setError(null);
    try {
        const data = await getRequestsForUser(user.id, user.role);
        setRequests(data);
    } catch (err: any) {
        console.error("Dashboard Fetch Error:", err);
        setError("Errore nel caricamento. Verifica la connessione o gli indici database.");
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleUpload = async () => {
    if (!selectedRequest || !videoFile) return;
    setIsSubmitting(true);
    try {
        await uploadVideo(videoFile, selectedRequest.id, qualityCheck);
        setSelectedRequest(null);
        refresh();
    } catch (e) {
        alert("Errore caricamento.");
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleSubmitDispute = async () => {
      if (!disputeModal || !disputeReason) return;
      await openDispute(disputeModal.id, disputeCategory, disputeReason);
      setDisputeModal(null);
      refresh();
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="animate-spin w-12 h-12 text-slate-900 mb-4" />
        <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Sincronizzazione CiaoStar...</p>
    </div>
  );

  // RENDERING LOGIC BASED ON ROLE
  return user.role === UserRole.TALENT ? (
    <TalentDashboardView 
      user={user} 
      requests={requests} 
      refresh={refresh} 
      error={error} 
      onUploadClick={setSelectedRequest}
      selectedRequest={selectedRequest}
      setSelectedRequest={setSelectedRequest}
      qualityCheck={qualityCheck}
      setQualityCheck={setQualityCheck}
      videoFile={videoFile}
      setVideoFile={setVideoFile}
      handleUpload={handleUpload}
      isSubmitting={isSubmitting}
    />
  ) : (
    <FanDashboardView 
      user={user} 
      requests={requests} 
      refresh={refresh} 
      error={error} 
      onDisputeClick={setDisputeModal}
      disputeModal={disputeModal}
      setDisputeModal={setDisputeModal}
      disputeCategory={disputeCategory}
      setDisputeCategory={setDisputeCategory}
      disputeReason={disputeReason}
      setDisputeReason={setDisputeReason}
      handleSubmitDispute={handleSubmitDispute}
    />
  );
};

