import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import TalentProfile from './pages/TalentProfile';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import Terms from './pages/Terms';
import AdminIdentity from './pages/AdminIdentity';
import AdminOrders from './pages/AdminOrders';
import AdminSettings from './pages/AdminSettings';
import AdminChat from './pages/AdminChat';
import UserChat from './pages/UserChat';
import TalentSettings from './pages/TalentSettings';
import { User, UserRole, AdminSettings as SettingsType } from './types';
import { auth } from './firebaseConfig';
import * as firebaseAuth from 'firebase/auth';
import { syncUserToDB, getAdminSettings, acceptNewTerms } from './services/dataService';
import { Loader2, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<SettingsType | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        const dbUser = await syncUserToDB({ 
          id: firebaseUser.uid, 
          email: firebaseUser.email || '', 
          name: firebaseUser.displayName || 'Utente',
          role: UserRole.FAN,
          lastAcceptedTermsVersion: 0
        });
        setUser(dbUser);
      } else {
        setUser(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const handleAcceptTerms = async () => {
    if (!user || !adminSettings) return;
    await acceptNewTerms(user.id, adminSettings.termsVersion);
    setUser({ ...user, lastAcceptedTermsVersion: adminSettings.termsVersion });
  };

  if (loading) return <div className="h-screen flex items-center justify-center bg-slate-950 text-violet-500"><Loader2 className="animate-spin" /></div>;

  const needsTermsUpdate = user?.role === UserRole.TALENT && adminSettings && user.lastAcceptedTermsVersion < adminSettings.termsVersion;

  return (
    <Router>
      <div className="min-h-screen bg-slate-950 flex flex-col font-sans text-slate-200">
        <Navbar user={user} onLogout={() => firebaseAuth.signOut(auth)} />

        {needsTermsUpdate && (
            <div className="fixed inset-0 z-[9999] bg-slate-950/90 backdrop-blur-md flex items-center justify-center p-4">
                <div className="bg-slate-900 rounded-[40px] p-10 max-w-md w-full shadow-2xl text-center border border-white/10">
                    <div className="w-20 h-20 bg-violet-900/30 text-amber-400 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner border border-amber-400/20">
                        <ShieldCheck className="w-10 h-10" />
                    </div>
                    <h2 className="text-2xl font-black text-white mb-6 uppercase tracking-tight">Regolamento Qualità</h2>
                    <div className="text-slate-400 mb-10 space-y-4 text-sm text-left leading-relaxed">
                        <p className="font-medium text-slate-300">Abbiamo aggiornato la <strong>Carta della Qualità</strong>:</p>
                        <ul className="space-y-3 font-bold text-slate-200">
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-violet-500 rounded-full"/> Nomi chiari e udibili.</li>
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-violet-500 rounded-full"/> Video superiore ai 20 secondi.</li>
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-violet-500 rounded-full"/> Divieto assoluto di AI/Deepfake.</li>
                        </ul>
                    </div>
                    <button 
                        onClick={handleAcceptTerms}
                        className="w-full bg-violet-600 text-white py-5 rounded-2xl font-black text-sm uppercase shadow-2xl hover:bg-violet-700 transition-all"
                    >
                        Accetto e Continuo
                    </button>
                </div>
            </div>
        )}

        <main className="flex-1">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login onLogin={() => {}} /> : <Navigate to="/" />} />
              <Route path="/terms" element={<Terms />} />
              <Route path="/talent/:id" element={<TalentProfile currentUser={user} />} />
              <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
              <Route path="/messages" element={user ? <UserChat user={user} /> : <Navigate to="/login" />} />
              <Route path="/settings" element={user?.role === UserRole.TALENT ? <TalentSettings user={user} /> : <Navigate to="/" />} />

              {/* ADMIN MODULAR AREA */}
              <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminIdentity /> : <Navigate to="/" />} />
              <Route path="/admin/orders" element={user?.role === UserRole.ADMIN ? <AdminOrders /> : <Navigate to="/" />} />
              <Route path="/admin/settings" element={user?.role === UserRole.ADMIN ? <AdminSettings /> : <Navigate to="/" />} />
              <Route path="/admin/chat" element={user?.role === UserRole.ADMIN ? <AdminChat user={user} /> : <Navigate to="/" />} />

              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </main>

        <Footer />
      </div>
    </Router>
  );
};

export default App;

