import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import TalentProfile from './pages/TalentProfile';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import Terms from './pages/Terms';
import AdminIdentity from './pages/AdminIdentity';
import AdminOrders from './pages/AdminOrders';
import AdminSettings from './pages/AdminSettings';
import AdminChat from './pages/AdminChat';
import UserChat from './pages/UserChat';
import TalentSettings from './pages/TalentSettings';
import { User, UserRole, AdminSettings as SettingsType } from './types';
import { auth } from './firebaseConfig';
import * as firebaseAuth from 'firebase/auth';
import { syncUserToDB, getAdminSettings, acceptNewTerms } from './services/dataService';
import { Loader2, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<SettingsType | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        const dbUser = await syncUserToDB({ 
          id: firebaseUser.uid, 
          email: firebaseUser.email || '', 
          name: firebaseUser.displayName || 'Utente',
          role: UserRole.FAN,
          lastAcceptedTermsVersion: 0
        });
        setUser(dbUser);
      } else {
        setUser(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const handleAcceptTerms = async () => {
    if (!user || !adminSettings) return;
    await acceptNewTerms(user.id, adminSettings.termsVersion);
    setUser({ ...user, lastAcceptedTermsVersion: adminSettings.termsVersion });
  };

  if (loading) return <div className="h-screen flex flex-col items-center justify-center bg-black"><Loader2 className="animate-spin text-gold/30 w-10 h-10" /><p className="mt-4 text-[10px] tracking-[0.4em] uppercase text-gold/40">Initializing Atelier</p></div>;

  const needsTermsUpdate = user?.role === UserRole.TALENT && adminSettings && user.lastAcceptedTermsVersion < adminSettings.termsVersion;

  return (
    <Router>
      <div className="min-h-screen bg-black flex flex-col">
        <Navbar user={user} onLogout={() => firebaseAuth.signOut(auth)} />

        {needsTermsUpdate && (
            <div className="fixed inset-0 z-[9999] bg-black/95 backdrop-blur-md flex items-center justify-center p-6">
                <div className="bg-[#050505] border border-white/5 p-12 max-w-lg w-full shadow-2xl text-center">
                    <div className="w-20 h-20 border border-gold/30 text-gold rounded-full flex items-center justify-center mx-auto mb-10 shadow-inner">
                        <ShieldCheck className="w-10 h-10" />
                    </div>
                    <h2 className="text-4xl font-serif text-white mb-6 italic">Excellence Registry</h2>
                    <div className="text-white/40 mb-12 space-y-4 text-xs tracking-widest leading-relaxed uppercase">
                        <p className="font-bold text-gold">Protocol Updates:</p>
                        <ul className="space-y-4">
                            <li>Clear and audible identifications</li>
                            <li>Minimum capture duration of 20 seconds</li>
                            <li>Strictly personal performance (No AI)</li>
                        </ul>
                    </div>
                    <button 
                        onClick={handleAcceptTerms}
                        className="btn-luxury w-full"
                    >
                        Acknowledge & Enter
                    </button>
                </div>
            </div>
        )}

        <main className="flex-1">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login /> : <Navigate to="/" />} />
              <Route path="/terms" element={<Terms />} />
              <Route path="/talent/:id" element={<TalentProfile currentUser={user} />} />
              <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
              <Route path="/messages" element={user ? <UserChat user={user} /> : <Navigate to="/login" />} />
              <Route path="/settings" element={user?.role === UserRole.TALENT ? <TalentSettings user={user} /> : <Navigate to="/" />} />

              <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminIdentity /> : <Navigate to="/" />} />
              <Route path="/admin/orders" element={user?.role === UserRole.ADMIN ? <AdminOrders /> : <Navigate to="/" />} />
              <Route path="/admin/settings" element={user?.role === UserRole.ADMIN ? <AdminSettings /> : <Navigate to="/" />} />
              <Route path="/admin/chat" element={user?.role === UserRole.ADMIN ? <AdminChat user={user} /> : <Navigate to="/" />} />

              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </main>

        <Footer />
      </div>
    </Router>
  );
};

export default App;

