import { getTalentById, createRequest, getAdminSettings } from '../services/dataService';
import { Talent, User, AdminSettings } from '../types';
import { OCCASIONS } from '../constants';
import { 
  Loader2, ArrowLeft, Diamond, Lock, PenTool, CheckCircle2, Zap
} from 'lucide-react';

const TalentProfile: React.FC<{ currentUser: User | null }> = ({ currentUser }) => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [talent, setTalent] = useState<Talent | undefined>();
  const [settings, setSettings] = useState<AdminSettings | null>(null);
  const [loading, setLoading] = useState(true);

  const [recipient, setRecipient] = useState('');
  const [instructions, setInstructions] = useState('');
  const [occasion, setOccasion] = useState(OCCASIONS[0]);
  const [agreed, setAgreed] = useState(false);

  useEffect(() => {
    const load = async () => {
      if (id) {
        const [t, s] = await Promise.all([getTalentById(id), getAdminSettings()]);
        setTalent(t);
        setSettings(s);
        setLoading(false);
      }
    };
    load();
  }, [id]);

  const handleBooking = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) { navigate('/login'); return; }
    if (!talent || !settings) return;

    try {
        await createRequest({
            talentId: talent.id,
            fanId: currentUser.id,
            fanName: currentUser.name,
            recipientName: recipient,
            instructions: instructions,
            occasion: occasion,
            pricePaid: talent.price
        });
        navigate('/dashboard');
    } catch (e) {
        alert("Booking Error.");
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-black"><Loader2 className="animate-spin w-12 h-12 text-gold/30" /></div>;
  if (!talent) return <div className="p-40 text-center font-serif text-white text-3xl italic">Atelier Entry Denied: Profile Not Found.</div>;

  return (
    <div className="min-h-screen bg-black pb-40">
      <div className="relative h-[70vh] overflow-hidden border-b border-white/5">
        <img src={talent.avatarUrl} className="w-full h-full object-cover opacity-60 grayscale scale-110" alt={talent.name} />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent"></div>
        <div className="absolute bottom-24 left-0 right-0 text-center px-6">
            <span className="text-[11px] tracking-[0.8em] text-gold font-bold uppercase mb-8 block">Exclusive Artist Profile</span>
            <h1 className="text-8xl md:text-[10rem] font-serif italic text-white leading-none tracking-tighter">{talent.name}</h1>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 lg:px-12 -mt-20 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-20">

            <div className="lg:col-span-4 space-y-16">
                <div className="bg-[#050505] border border-white/5 p-12 shadow-2xl">
                    <h3 className="text-[11px] tracking-[0.5em] font-bold text-gold uppercase mb-12 border-b border-white/5 pb-6">Commission Specs</h3>
                    <div className="space-y-10">
                        <div className="flex justify-between items-end border-b border-white/5 pb-6">
                            <span className="text-[10px] font-bold text-white/20 uppercase tracking-widest">Investment</span>
                            <span className="text-3xl font-serif text-white">€{talent.price}</span>
                        </div>
                        <div className="flex justify-between items-end border-b border-white/5 pb-6">
                            <span className="text-[10px] font-bold text-white/20 uppercase tracking-widest">Wait Time</span>
                            <span className="text-sm font-bold text-white tracking-[0.2em] uppercase">{talent.responseTimeDays} Days</span>
                        </div>
                        <div className="flex justify-between items-center border-b border-white/5 pb-6">
                            <span className="text-[10px] font-bold text-white/20 uppercase tracking-widest">Atelier Status</span>
                            <div className="flex items-center gap-2 text-emerald-500 font-bold text-[10px] tracking-widest">
                                <CheckCircle2 className="w-4 h-4"/> VERIFIED
                            </div>
                        </div>
                    </div>
                </div>

                <div className="p-12 border border-gold/10 bg-gold/5">
                    <Lock className="w-6 h-6 text-gold mb-10 opacity-50" />
                    <h4 className="text-[11px] font-bold text-white uppercase tracking-[0.4em] mb-6">Platinum Escrow Protection</h4>
                    <p className="text-[10px] text-white/40 leading-[2] tracking-[0.15em] uppercase font-medium">
                        Your funds are held in our secure vault and only released upon successful capture and your final approval of the masterpiece.
                    </p>
                </div>
            </div>

            <div className="lg:col-span-8">
                <div className="bg-[#050505] border border-white/5 p-16 lg:p-24 shadow-2xl">
                    <div className="flex items-center gap-6 mb-20">
                        <PenTool className="w-8 h-8 text-gold/30" />
                        <h2 className="text-6xl font-serif text-white italic">New Commission</h2>
                    </div>

                    <form onSubmit={handleBooking} className="space-y-24">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
                            <div className="space-y-6">
                                <label className="text-[11px] tracking-[0.4em] font-bold text-white/20 uppercase">The Occasion</label>
                                <select 
                                    className="input-atelier"
                                    value={occasion} onChange={e => setOccasion(e.target.value)}
                                >
                                    {OCCASIONS.map(occ => <option key={occ} value={occ} className="bg-black text-white">{occ}</option>)}
                                </select>
                            </div>
                            <div className="space-y-6">
                                <label className="text-[11px] tracking-[0.4em] font-bold text-white/20 uppercase">Recipient Name</label>
                                <input 
                                    className="input-atelier"
                                    placeholder="Enter full name" value={recipient} onChange={e => setRecipient(e.target.value)} required
                                />
                            </div>
                        </div>

                        <div className="space-y-10">
                            <label className="text-[11px] tracking-[0.4em] font-bold text-white/20 uppercase">Directives & Instructions</label>
                            <textarea 
                                className="w-full bg-white/[0.03] border border-white/5 p-10 text-white font-light tracking-[0.2em] min-h-[250px] outline-none focus:border-gold/30 transition-all resize-none text-sm uppercase leading-[2]"
                                placeholder="Describe the scene, tone, and specific details for the artist..."
                                value={instructions} onChange={e => setInstructions(e.target.value)} required
                            />
                        </div>

                        <div className="pt-16 space-y-10 border-t border-white/5">
                            <label className="flex items-start gap-6 cursor-pointer group">
                                <input type="checkbox" checked={agreed} onChange={e => setAgreed(e.target.checked)} className="sr-only" />
                                <div className={`w-6 h-6 border border-white/10 flex items-center justify-center transition-all mt-1 ${agreed ? 'bg-gold border-gold' : 'group-hover:border-gold/50'}`}>
                                    {agreed && <div className="w-2.5 h-2.5 bg-black"></div>}
                                </div>
                                <div className="flex-1">
                                    <span className="text-[10px] tracking-[0.3em] font-bold text-white/30 uppercase leading-loose block mb-1">Membership Accord</span>
                                    <p className="text-[9px] text-white/10 uppercase tracking-widest leading-relaxed">I acknowledge that this commission is for private use only and governed by the Atelier Membership Terms.</p>
                                </div>
                            </label>

                            <button 
                                disabled={!agreed}
                                className="btn-luxury w-full py-10 border border-gold/40 text-[11px]"
                            >
                                <Zap className="w-4 h-4 text-gold" />
                                INITIATE COMMISSION • €{talent.price}
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default TalentProfile;

import React from 'react';
