                <div className="mt-16 pt-10 border-t border-white/5 space-y-6">
                    <p className="text-[8px] tracking-[0.3em] text-white/10 font-medium uppercase leading-relaxed">
                        End-to-end encrypted session. <br/>
                        By entering, you adhere to the Excellence Protocol.
                    </p>
                </div>
            </div>
        </div>
