import React, { useState, useMemo, useEffect } from 'react';
import { getTalents, getCategories } from '../services/dataService';
import TalentCard from '../components/TalentCard';
import { Search, Loader2 } from 'lucide-react';
import { Talent } from '../types';

const Home: React.FC = () => {
  const [talents, setTalents] = useState<Talent[]>([]);
  const [categories, setCategories] = useState<string[]>(['Tutti']);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('Tutti');
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const [talentsData, catsData] = await Promise.all([getTalents(), getCategories()]);
      const usedCategories = new Set(talentsData.map(t => t.category));
      const activeCategories = catsData.filter(cat => usedCategories.has(cat));
      setTalents(talentsData);
      setCategories(['Tutti', ...activeCategories]);
      setLoading(false);
    };
    fetchData();
  }, []);

  const filteredTalents = useMemo(() => {
    return talents.filter(t => {
      const matchesCategory = selectedCategory === 'Tutti' || t.category === selectedCategory;
      const matchesSearch = t.name.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [talents, selectedCategory, searchTerm]);

  return (
    <div className="min-h-screen bg-black">
      {/* Editorial Hero */}
      <div className="relative h-[90vh] flex items-center justify-center border-b border-white/5 bg-[#020202]">
        <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-20">
          <div className="absolute top-1/4 left-1/3 w-[50vw] h-[50vw] bg-gold/5 rounded-full blur-[180px]"></div>
          <div className="absolute bottom-0 right-0 w-[60vw] h-[60vw] bg-white/5 rounded-full blur-[200px]"></div>
        </div>

        <div className="relative z-10 text-center px-6 max-w-6xl">
          <div className="flex items-center justify-center space-x-6 mb-16">
            <div className="h-px w-16 bg-gold/20"></div>
            <span className="text-[11px] tracking-[0.8em] text-gold font-bold uppercase">Collezione Privata</span>
            <div className="h-px w-16 bg-gold/20"></div>
          </div>

          <h1 className="text-7xl md:text-[11rem] font-serif italic text-white mb-12 leading-[0.85] tracking-tighter">
            L'Arte dell'<br/>
            <span className="luxury-shimmer">Eccellenza.</span>
          </h1>

          <p className="text-xl text-white/30 mb-20 max-w-xl mx-auto font-light tracking-[0.15em] leading-relaxed uppercase text-[10px]">
            Commissiona un capolavoro digitale personalizzato dalle figure più influenti e distinte del mondo.
          </p>

          <div className="relative max-w-lg mx-auto group">
            <input
              type="text"
              className="w-full bg-white/5 border-b border-white/10 py-8 px-6 text-white text-center focus:outline-none focus:border-gold transition-all font-light tracking-[0.4em] uppercase text-[10px] placeholder:text-white/10"
              placeholder="CERCA NELL'ATELIER"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <Search className="absolute right-0 top-1/2 -translate-y-1/2 w-4 h-4 text-gold/30" />
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 lg:px-12 py-40">
        <div className="flex flex-wrap justify-center gap-14 mb-32">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`text-[10px] tracking-[0.5em] font-bold uppercase transition-all pb-3 border-b-2 ${
                selectedCategory === cat ? 'text-gold border-gold' : 'text-white/20 border-transparent hover:text-white'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {loading ? (
            <div className="flex flex-col items-center justify-center py-40 space-y-6">
                <Loader2 className="w-8 h-8 animate-spin text-gold/20" />
                <p className="text-[9px] tracking-[0.5em] text-gold/30 uppercase">Curatela della Collezione</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-10 gap-y-24">
              {filteredTalents.map(talent => (
                  <TalentCard key={talent.id} talent={talent} />
              ))}
            </div>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getTalentById, createRequest, getAdminSettings } from '../services/dataService';
import { Talent, User, AdminSettings } from '../types';
import { OCCASIONS } from '../constants';
import { 
  Loader2, ArrowLeft, Diamond, Lock, PenTool, CheckCircle2, Zap
} from 'lucide-react';

const TalentProfile: React.FC<{ currentUser: User | null }> = ({ currentUser }) => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [talent, setTalent] = useState<Talent | undefined>();
  const [settings, setSettings] = useState<AdminSettings | null>(null);
  const [loading, setLoading] = useState(true);

  const [recipient, setRecipient] = useState('');
  const [instructions, setInstructions] = useState('');
  const [occasion, setOccasion] = useState(OCCASIONS[0]);
  const [agreed, setAgreed] = useState(false);

  useEffect(() => {
    const load = async () => {
      if (id) {
        const [t, s] = await Promise.all([getTalentById(id), getAdminSettings()]);
        setTalent(t);
        setSettings(s);
        setLoading(false);
      }
    };
    load();
  }, [id]);

  const handleBooking = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) { navigate('/login'); return; }
    if (!talent || !settings) return;

    try {
        await createRequest({
            talentId: talent.id,
            fanId: currentUser.id,
            fanName: currentUser.name,
            recipientName: recipient,
            instructions: instructions,
            occasion: occasion,
            pricePaid: talent.price
        });
        navigate('/dashboard');
    } catch (e) {
        alert("Errore nella prenotazione.");
    }
  };

