import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Diamond, Download, Gift
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);

  const refresh = async () => {
    setLoading(true);
    try {
        const data = await getRequestsForUser(user.id, user.role);
        setRequests(data);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-black">
        <Loader2 className="animate-spin w-10 h-10 text-gold/20 mb-8" />
        <p className="text-[10px] tracking-[0.6em] text-gold/40 font-black uppercase">Ingresso nella Suite Privata</p>
    </div>
  );

  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: requests.filter(r => r.status === RequestStatus.COMPLETED).length,
      earnings: requests.filter(r => r.status === RequestStatus.COMPLETED).reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12 py-24 text-white">
        <div className="mb-24 flex justify-between items-end">
            <div>
                <span className="text-[10px] tracking-[0.6em] text-gold font-bold uppercase mb-4 block">Dashboard Membri</span>
                <h1 className="text-7xl font-serif italic luxury-shimmer">La Suite Privata</h1>
            </div>
            <button onClick={refresh} className="p-5 border border-white/5 hover:border-gold/30 transition-colors">
                <RefreshCw className="w-4 h-4 text-white/20 hover:text-gold" />
            </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-px bg-white/5 border border-white/5 mb-32 overflow-hidden shadow-2xl">
            {[
                { label: 'Richieste Totali', value: stats.total, icon: Package },
                { label: 'In Produzione', value: stats.pending, icon: Clock },
                { label: 'Archiviate', value: stats.completed, icon: CheckCircle },
                { label: user.role === UserRole.TALENT ? 'Ricavo Netto' : 'Investimento', value: `€${stats.earnings.toFixed(0)}`, icon: user.role === UserRole.TALENT ? Wallet : Gift }
            ].map((stat, i) => (
                <div key={i} className="bg-[#020202] p-12 flex flex-col items-center text-center group hover:bg-[#050505] transition-colors">
                    <stat.icon className="w-5 h-5 text-gold/30 mb-8 group-hover:text-gold transition-colors" />
                    <p className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-3">{stat.label}</p>
                    <p className="text-4xl font-serif text-white">{stat.value}</p>
                </div>
            ))}
        </div>

        <div className="space-y-16">
            <h2 className="text-[11px] tracking-[0.5em] font-bold text-gold/40 uppercase mb-12 border-b border-white/5 pb-6">Registro Corrente</h2>

            {requests.length === 0 ? (
                <div className="text-center py-40 border border-white/5 bg-[#030303]">
                    <p className="text-[10px] tracking-[0.5em] text-white/10 uppercase italic">Nessun record trovato in questo atelier.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
                    {requests.map(req => (
                        <div key={req.id} className="bg-[#050505] border border-white/5 p-16 transition-all hover:border-gold/20 flex flex-col">
                            <div className="flex justify-between items-start mb-14">
                                <Diamond className="w-6 h-6 text-gold/20" />
                                <span className={`text-[9px] tracking-[0.3em] font-bold uppercase px-4 py-2 border ${
                                    req.status === RequestStatus.COMPLETED ? 'text-emerald-500 border-emerald-500/20 bg-emerald-500/5' :
                                    req.status === RequestStatus.PENDING ? 'text-gold border-gold/20 bg-gold/5' :
                                    'text-white/20 border-white/10'
                                }`}>{req.status}</span>
                            </div>

                            <p className="text-[10px] tracking-[0.5em] text-gold/40 font-black uppercase mb-4">{req.occasion}</p>
                            <h3 className="text-5xl font-serif text-white mb-6 italic">Per: {req.recipientName}</h3>

                            <div className="flex-1 bg-white/5 p-8 italic text-white/40 text-sm mb-12 border-l border-gold/30 font-light">
                                "{req.instructions}"
                            </div>

                            {req.videoUrl ? (
                                <div className="space-y-8">
                                    <div className="border border-white/10 p-1 bg-black">
                                        <VideoPlayer src={req.videoUrl} />
                                    </div>
                                    <button className="btn-luxury w-full py-5">
                                        <Download className="w-4 h-4" /> Scarica Archivio
                                    </button>
                                </div>
                            ) : (
                                <div className="py-20 flex flex-col items-center justify-center border border-dashed border-white/10 bg-white/5 opacity-40">
                                    <Loader2 className="w-8 h-8 animate-spin text-gold/40 mb-6" />
                                    <span className="text-[10px] tracking-[0.5em] font-bold uppercase">L'Artista sta producendo il contenuto</span>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}
        </div>
    </div>
  );
};

export default Dashboard;

