import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Star, Download, Gift, PlayCircle
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);

  const refresh = async () => {
    setLoading(true);
    try {
        const data = await getRequestsForUser(user.id, user.role);
        setRequests(data);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: requests.filter(r => r.status === RequestStatus.COMPLETED).length,
      earnings: requests.filter(r => r.status === RequestStatus.COMPLETED).reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">La tua Dashboard</h1>
                <p className="text-slate-500 font-medium">Gestisci i tuoi video messaggi e lo stato delle richieste.</p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
            {[
                { label: 'Totali', value: stats.total, icon: Package, color: 'bg-indigo-50 text-indigo-600' },
                { label: 'In attesa', value: stats.pending, icon: Clock, color: 'bg-amber-50 text-amber-600' },
                { label: 'Completati', value: stats.completed, icon: CheckCircle, color: 'bg-emerald-50 text-emerald-600' },
                { label: user.role === UserRole.TALENT ? 'Guadagno' : 'Spesa', value: `€${stats.earnings.toFixed(0)}`, icon: Wallet, color: 'bg-indigo-600 text-white' }
            ].map((stat, i) => (
                <div key={i} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                    <div className={`${stat.color} w-10 h-10 rounded-xl flex items-center justify-center mb-4`}>
                        <stat.icon className="w-5 h-5" />
                    </div>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">{stat.label}</p>
                    <p className="text-2xl font-black text-slate-900">{stat.value}</p>
                </div>
            ))}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">Le tue richieste</h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. Inizia subito!</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => (
                        <div key={req.id} className="bg-white rounded-3xl border border-gray-100 p-8 shadow-sm transition-all hover:shadow-md">
                            <div className="flex justify-between items-start mb-6">
                                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                    req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                    req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                    'bg-gray-100 text-slate-400'
                                }`}>{req.status}</div>
                                <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8)}</span>
                            </div>

                            <h3 className="text-2xl font-extrabold text-slate-900 mb-2">Per: {req.recipientName}</h3>
                            <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider mb-6">{req.occasion}</p>

                            <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200">
                                "{req.instructions}"
                            </div>

                            {req.videoUrl ? (
                                <div className="space-y-4">
                                    <div className="rounded-2xl overflow-hidden shadow-inner bg-black">
                                        <VideoPlayer src={req.videoUrl} />
                                    </div>
                                    <button className="btn-primary w-full py-4">
                                        <Download className="w-4 h-4" /> Scarica Video
                                    </button>
                                </div>
                            ) : (
                                <div className="py-12 flex flex-col items-center justify-center bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100 text-slate-400">
                                    <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                    <span className="text-sm font-bold">Video in produzione...</span>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}
        </div>
    </div>
  );
};

export default Dashboard;

