export const uploadWatermark = async (file: File): Promise<string> => {
    const storageRef = ref(storage, `settings/watermark_${Date.now()}`);
    await uploadBytes(storageRef, file);
    const url = await getDownloadURL(storageRef);
    await updateDoc(doc(db, 'settings', 'global_config'), { watermarkUrl: url });
    return url;
};

export const deleteWatermark = async () => {
    await updateDoc(doc(db, 'settings', 'global_config'), { watermarkUrl: null });
};

import React, { useState, useEffect, useRef } from 'react';
import { User, ChatMessage, Conversation, UserRole } from '../types';
import { subscribeToConversations, subscribeToMessages, sendMessage, markConversationAsRead, updateChatMessage, deleteChatMessage } from '../services/dataService';
import { Send, Search, User as UserIcon, ShieldAlert, Circle, Loader2, MessageCircle as MsgIcon, Pencil, Trash2, X, Check } from 'lucide-react';

interface AdminChatProps {
    user: User;
}

const AdminChat: React.FC<AdminChatProps> = ({ user }) => {
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [selectedConvId, setSelectedConvId] = useState<string | null>(null);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const [loadingConvs, setLoadingConvs] = useState(true);

    const [editingMsgId, setEditingMsgId] = useState<string | null>(null);
    const [editText, setEditText] = useState('');

    useEffect(() => {
        const unsubscribe = subscribeToConversations((convs) => {
            setConversations(convs);
            setLoadingConvs(false);
        });
        return () => unsubscribe();
    }, []);

    useEffect(() => {
        if (!selectedConvId) return;

        markConversationAsRead(selectedConvId, UserRole.ADMIN);

        const unsubscribe = subscribeToMessages(selectedConvId, (msgs) => {
            setMessages(msgs);
            setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
        });

        setEditingMsgId(null);
        return () => unsubscribe();
    }, [selectedConvId]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedConvId || !newMessage.trim()) return;

        try {
            await sendMessage(selectedConvId, user.id, newMessage, true);
            setNewMessage('');
            setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
        } catch (err) {
            console.error(err);
            alert("Errore invio.");
        }
    };

    const startEditing = (msg: ChatMessage) => {
        setEditingMsgId(msg.id);
        setEditText(msg.text);
    };

    const cancelEditing = () => {
        setEditingMsgId(null);
        setEditText('');
    };

    const saveEdit = async (msgId: string) => {
        if (!selectedConvId || !editText.trim()) return;
        try {
            await updateChatMessage(selectedConvId, msgId, editText);
            cancelEditing();
        } catch (e) {
            console.error("Error editing message:", e);
            alert("Errore modifica messaggio");
        }
    };

    const handleDelete = async (msgId: string) => {
        if (!selectedConvId) return;
        if (confirm("Sei sicuro di voler eliminare questo messaggio?")) {
            try {
                await deleteChatMessage(selectedConvId, msgId);
            } catch (e) {
                console.error("Error deleting message:", e);
                alert("Errore eliminazione messaggio");
            }
        }
    };

    const filteredConversations = conversations.filter(c => 
        (c.userName || 'Utente').toLowerCase().includes(searchTerm.toLowerCase())
    );

    const selectedConversation = conversations.find(c => c.id === selectedConvId);

    if (user.role !== UserRole.ADMIN) return <div>Accesso negato</div>;

    return (
        <div className="flex h-[calc(100vh-64px)] max-w-7xl mx-auto bg-white shadow-sm overflow-hidden">

            <div className="w-1/3 border-r border-gray-200 flex flex-col bg-gray-50">
                <div className="p-4 border-b border-gray-200 bg-white">
                    <h2 className="text-xl font-bold text-slate-900 mb-4 uppercase tracking-tight">Messaggi Utenti</h2>
                    <div className="relative">
                        <Search className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                        <input 
                            type="text" 
                            placeholder="Cerca utente..." 
                            className="w-full pl-9 pr-4 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-gray-50 transition-all"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto no-scrollbar">
                    {loadingConvs ? (
                        <div className="flex justify-center p-8"><Loader2 className="animate-spin text-indigo-500"/></div>
                    ) : filteredConversations.length === 0 ? (
                        <div className="p-10 text-center text-gray-400 text-xs font-bold uppercase tracking-widest">Nessuna conversazione trovata.</div>
                    ) : (
                        filteredConversations.map(conv => (
                            <div 
                                key={conv.id}
                                onClick={() => setSelectedConvId(conv.id)}
                                className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-white transition-all flex items-start gap-3 ${selectedConvId === conv.id ? 'bg-indigo-50/50 border-l-4 border-l-indigo-600' : ''}`}
                            >
                                <div className="relative flex-shrink-0">
                                    <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold overflow-hidden border border-indigo-50">
                                        {conv.userAvatar ? <img src={conv.userAvatar} className="w-full h-full object-cover"/> : <UserIcon className="w-5 h-5"/>}
                                    </div>
                                    {conv.unreadCountAdmin > 0 && (
