                                    </div>
                                    <p className={`text-xs truncate ${conv.unreadCountAdmin > 0 ? 'text-indigo-700 font-bold' : 'text-slate-500 font-medium'}`}>
                                        {conv.lastMessage}
                                    </p>
                                    <span className={`text-[9px] mt-1.5 inline-block px-2 py-0.5 rounded-full font-bold uppercase tracking-wider ${conv.userRole === UserRole.TALENT ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                        {conv.userRole}
                                    </span>
                                </div>
                            </div>
