                    )}
                </div>
            </div>

            <div className="flex-1 flex flex-col bg-white">
                {selectedConvId && selectedConversation ? (
                    <>
                        <div className="h-16 border-b border-gray-100 flex items-center px-6 justify-between bg-white z-10 shadow-sm">
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
                                    {(selectedConversation.userName || 'U').charAt(0)}
