                                <div>
                                    <h3 className="font-extrabold text-slate-900 text-sm leading-none mb-1">{selectedConversation.userName}</h3>
                                    <span className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">{selectedConversation.userRole}</span>
                                </div>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-50/50">
                            {messages.map((msg) => {
                                const isMe = !!msg.isAdmin; 
                                const isEditing = editingMsgId === msg.id;

                                return (
                                    <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} group relative`}>
                                        <div className={`max-w-[70%] rounded-2xl px-5 py-3 shadow-sm relative ${
