                                                    <button onClick={() => saveEdit(msg.id)} className="text-white hover:text-emerald-300 transition-colors"><Check className="w-4 h-4"/></button>
                                                    <button onClick={cancelEditing} className="text-white hover:text-red-300 transition-colors"><X className="w-4 h-4"/></button>
