                                            <input 
                                                className="bg-indigo-700 text-white border border-indigo-400 rounded-xl px-3 py-1.5 text-sm focus:outline-none w-full min-w-[200px] font-medium"
                                                value={editText}
                                                onChange={(e) => setEditText(e.target.value)}
