export const uploadVideo = async (file: File, requestId: string, qualityCheck: VideoRequest['talentQualityCheck']) => {
    const settings = await getAdminSettings();
    const watermarkUrl = settings.watermarkUrl;

    let fileToUpload: Blob = file;
    let finalExtension = file.name.split('.').pop() || 'mp4';

    // Se esiste una filigrana, processiamo il video prima dell'upload
    if (watermarkUrl) {
        try {
            const processed = await addWatermarkToVideo(file, watermarkUrl);
            fileToUpload = processed.blob;
            finalExtension = processed.extension;
        } catch (e) {
            console.error("Watermark processing failed, uploading original:", e);
        }
    }

    const storageRef = ref(storage, `videos/${requestId}_${Date.now()}.${finalExtension}`);
    await uploadBytes(storageRef, fileToUpload);
    const url = await getDownloadURL(storageRef);

    await updateDoc(doc(db, 'orders', requestId), { 
        videoUrl: url, 
        status: RequestStatus.COMPLETED, // Passa a COMPLETED dopo il caricamento
        updatedAt: new Date().toISOString(),
        talentQualityCheck: qualityCheck
    });
};

