              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo! Verrà ora processato e reso disponibile al fan.");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload: " + (e.message || "Errore sconosciuto"));
      } finally {
          setIsUploading(false);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                <div>
                    <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">{isTalent ? 'Guadagno Netto' : 'Spesa Totale'}</p>
                    <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                </div>
                {isTalent && stats.completed > 0 && (
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. {isTalent ? 'Appena arriverà un ordine lo vedrai qui!' : 'Inizia subito!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => (
                        <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                            req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                        }`}>
                            <div className="flex justify-between items-start mb-6">
                                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                    req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                    req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                    req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                    req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                    'bg-gray-100 text-slate-400'
                                }`}>{req.status}</div>
                                <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8)}</span>
                            </div>

                            <div className="flex justify-between items-end mb-6">
                                <div>
                                    <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                        {isTalent ? `Per: ${req.recipientName}` : `Da: ${req.talentName || req.talentId}`}
                                    </h3>
                                    <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-[10px] font-black text-slate-400 uppercase">{isTalent ? 'Tua Quota' : 'Prezzo'}</p>
                                    <p className="text-xl font-black text-slate-900">
                                        €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                    </p>
                                    {isTalent && (
                                        <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                            <ArrowDownRight className="w-2.5 h-2.5" />
                                            Lordo €{req.pricePaid.toFixed(2)}
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative group">
                                <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                "{req.instructions}"
                            </div>

                            {/* Azioni Talent */}
                            {isTalent && (
                                <div className="space-y-4">
                                    {req.status === RequestStatus.PENDING && (
                                        <div className="grid grid-cols-2 gap-3">
                                            <button 
                                                onClick={() => setRejectingId(req.id)}
                                                className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                            >
                                                <X className="w-4 h-4" /> Rifiuta
                                            </button>
                                            <button 
                                                onClick={() => handleAccept(req.id)}
                                                className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                            >
                                                <Check className="w-4 h-4" /> Accetta
                                            </button>
                                        </div>
                                    )}

                                    {/* Messaggio Rifiuto lato Talent (per log) */}
                                    {req.status === RequestStatus.REJECTED && req.rejectionReason && (
                                        <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex gap-3">
                                            <X className="w-4 h-4 text-red-600 mt-1" />
                                            <div>
                                                <p className="text-[9px] font-black text-red-400 uppercase">Hai rifiutato per:</p>
                                                <p className="text-xs font-bold text-red-900">"{req.rejectionReason}"</p>
                                            </div>
                                        </div>
                                    )}

                                    {req.status === RequestStatus.ACCEPTED && (
                                        <div>
                                            {uploadingId === req.id ? (
                                                <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6 animate-in fade-in slide-in-from-top-4">
                                                    <div className="flex items-center justify-between">
                                                        <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Upload Video</h4>
                                                        <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                    </div>

                                                    <div className="space-y-4">
                                                        <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                            <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                            <span className="text-sm font-bold text-slate-500">
                                                                {uploadFile ? uploadFile.name : 'Seleziona file video (MP4/MOV)'}
                                                            </span>
                                                            <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                        </label>

                                                        <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                            <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                <ShieldCheck className="w-3 h-3" /> Controllo Qualità Obbligatorio
                                                            </p>
                                                            {[
                                                                { key: 'nameSaid', label: 'Ho pronunciato il nome del destinatario' },
                                                                { key: 'durationOk', label: 'Il video dura almeno 20 secondi' },
                                                                { key: 'audioClear', label: 'L\'audio è chiaro e senza rumori' }
                                                            ].map(item => (
                                                                <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                    <input 
                                                                        type="checkbox" 
                                                                        checked={(qualityCheck as any)[item.key]} 
                                                                        onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                        className="sr-only"
                                                                    />
                                                                    <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                        (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                    }`}>
                                                                        {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                    </div>
                                                                    <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                </label>
                                                            ))}
                                                        </div>
                                                    </div>

                                                    <button 
                                                        disabled={isUploading || !uploadFile}
                                                        onClick={() => handleUploadSubmit(req.id)}
                                                        className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                    >
                                                        {isUploading ? (
                                                            <>
                                                                <Loader2 className="animate-spin w-4 h-4" /> 
                                                                Processing & Uploading...
                                                            </>
                                                        ) : (
                                                            <>
                                                                <Video className="w-4 h-4" /> 
                                                                Invia Video al Fan
                                                            </>
                                                        )}
                                                    </button>

                                                    <div className="flex items-center gap-2 text-[10px] text-amber-600 font-bold bg-amber-50 p-2 rounded-lg">
                                                        <AlertCircle className="w-3 h-3" />
                                                        Il sistema aggiungerà automaticamente la filigrana CiaoStar.
                                                    </div>
                                                </div>
                                            ) : (
                                                <button 
                                                    onClick={() => setUploadingId(req.id)}
                                                    className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-emerald-500 text-white font-bold text-sm hover:bg-emerald-600 shadow-lg shadow-emerald-50 transition-all"
                                                >
                                                    <Upload className="w-4 h-4" /> Carica Video Completato
                                                </button>
                                            )}
                                        </div>
                                    )}
                                </div>
                            )}

                            {/* Visualizzazione Video o Placeholder Rifiuto Lato Fan */}
                            {req.videoUrl ? (
                                <div className="space-y-4">
                                    <div className="rounded-2xl overflow-hidden shadow-inner bg-black aspect-video relative group">
                                        <VideoPlayer src={req.videoUrl} />
                                    </div>
                                    {!isTalent && (
                                        <button className="btn-primary w-full py-4">
                                            <Download className="w-4 h-4" /> Scarica il tuo regalo
                                        </button>
                                    )}
                                </div>
                            ) : (
                                (!isTalent || (req.status !== RequestStatus.PENDING && req.status !== RequestStatus.ACCEPTED)) ? (
                                    <div className={`py-12 flex flex-col items-center justify-center rounded-2xl border-2 border-dashed ${
                                        req.status === RequestStatus.REJECTED ? 'bg-red-50/30 border-red-100 text-red-400' : 'bg-gray-50 border-gray-100 text-slate-400'
                                    }`}>
                                        {req.status === RequestStatus.REJECTED ? (
                                            <div className="text-center px-6">
                                                <AlertCircle className="w-10 h-10 mb-3 mx-auto opacity-40" />
                                                <span className="block text-sm font-black uppercase tracking-widest mb-4">Richiesta Rifiutata</span>

                                                {req.rejectionReason && (
                                                    <div className="bg-white p-4 rounded-xl shadow-sm border border-red-100 max-w-xs mx-auto text-left">
                                                        <p className="text-[9px] font-black text-red-500 uppercase mb-1 flex items-center gap-1">
                                                            <MessageSquare className="w-3 h-3" /> Messaggio dalla Star:
                                                        </p>
                                                        <p className="text-xs font-bold text-red-900 leading-relaxed italic">
                                                            "{req.rejectionReason}"
                                                        </p>
                                                    </div>
                                                )}
                                                {!isTalent && (
                                                    <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-bold text-slate-400 bg-white/50 px-3 py-1.5 rounded-full border border-gray-100">
                                                        <CornerUpLeft className="w-3 h-3" /> I fondi ti sono stati rimborsati
                                                    </div>
                                                )}
                                            </div>
                                        ) : (
                                            <>
                                                <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                                <span className="text-sm font-bold uppercase tracking-widest text-slate-300">
                                                    In attesa del video...
                                                </span>
                                            </>
                                        )}
                                    </div>
                                ) : null
                            )}
                        </div>
                    ))}
                </div>
            )}
        </div>

        {/* MODALE RIFIUTO (Talent) */}
        {rejectingId && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
                    <div className="p-8 border-b border-gray-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-red-500 p-2 rounded-xl">
                                <AlertCircle className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="font-extrabold text-slate-900 uppercase tracking-tight">Motiva il rifiuto</h3>
                        </div>
                        <button 
                            onClick={() => !isRejecting && setRejectingId(null)}
                            className="text-slate-400 hover:text-slate-900 transition-colors"
                        >
                            <X className="w-6 h-6" />
                        </button>
                    </div>

                    <div className="p-8">
                        <p className="text-sm text-slate-500 font-medium mb-6">
                            Perché non puoi accettare questa richiesta? Il Fan vedrà questo motivo e potrà capire cosa migliorare.
                        </p>

                        <div className="space-y-6">
                            {/* Suggerimenti veloci */}
                            <div className="flex flex-wrap gap-2">
                                {[
                                    'Richiesta inappropriata', 
                                    'Istruzioni poco chiare', 
                                    'Problemi tecnici', 
                                    'Troppi ordini attivi'
                                ].map(chip => (
                                    <button 
                                        key={chip}
                                        onClick={() => setRejectionReason(chip)}
                                        className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                                            rejectionReason === chip 
                                            ? 'bg-red-600 border-red-600 text-white shadow-md' 
                                            : 'bg-gray-50 border-gray-100 text-slate-500 hover:border-red-200'
                                        }`}
                                    >
                                        {chip}
                                    </button>
                                ))}
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-bold text-slate-700 ml-1">Messaggio personalizzato</label>
                                <textarea 
                                    className="input-main min-h-[100px] resize-none text-sm"
                                    placeholder="Scrivi qui..."
                                    value={rejectionReason}
                                    onChange={(e) => setRejectionReason(e.target.value)}
                                    required
                                />
                            </div>

                            <div className="flex gap-3">
                                <button 
                                    onClick={() => setRejectingId(null)}
                                    disabled={isRejecting}
                                    className="btn-secondary flex-1 py-4 text-sm"
                                >
                                    Annulla
                                </button>
                                <button 
                                    onClick={submitRejection}
                                    disabled={isRejecting || !rejectionReason.trim()}
                                    className="bg-red-600 text-white flex-[2] py-4 rounded-2xl font-black text-sm uppercase shadow-xl shadow-red-100 hover:bg-red-700 transition-all disabled:opacity-50"
                                >
                                    {isRejecting ? <Loader2 className="animate-spin mx-auto w-4 h-4" /> : 'Rifiuta Ordine'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Star, Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, Info, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  const refresh = async () => {
    setLoading(true);
    try {
        const data = await getRequestsForUser(user.id, user.role);
        setRequests(data);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo! Verrà ora processato e reso disponibile al fan.");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload: " + (e.message || "Errore sconosciuto"));
      } finally {
          setIsUploading(false);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                <div>
                    <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">{isTalent ? 'Guadagno Netto' : 'Spesa Totale'}</p>
                    <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                </div>
                {isTalent && stats.completed > 0 && (
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
