                                }`}>{req.status}</div>
                                <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8)}</span>
                            </div>

                            <div className="flex justify-between items-end mb-6">
                                <div>
                                    <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                        {isTalent ? `Per: ${req.recipientName}` : `Da: ${req.talentName || 'Star di CiaoStar'}`}
                                    </h3>
                                    <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-[10px] font-black text-slate-400 uppercase">{isTalent ? 'Tua Quota' : 'Valore'}</p>
                                    <p className="text-xl font-black text-slate-900">
                                        €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                    </p>
                                    {isTalent && (
                                        <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                            <ArrowDownRight className="w-2.5 h-2.5" />
