import React from 'react';
import { GoogleGenAI } from "@google/genai";

// Configurazione Iniziale
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

document.addEventListener('DOMContentLoaded', () => {
    const fileInput = document.getElementById('file-input') as HTMLInputElement;
    const dropZone = document.getElementById('drop-zone');
    const analyzeBtn = document.getElementById('analyze-btn') as HTMLButtonElement;
    const previewImg = document.getElementById('preview-img') as HTMLImageElement;
    const previewContainer = document.getElementById('preview-container');
    const placeholder = document.getElementById('placeholder');
    const overlayCanvas = document.getElementById('overlay-canvas') as HTMLCanvasElement;
    const scanner = document.getElementById('scanner');
    const jsonOutput = document.getElementById('json-output');
    const statusLogs = document.getElementById('status-logs');

    let currentFileBase64: string | null = null;

    const log = (message: string, type: 'info' | 'success' | 'error' = 'info') => {
        const div = document.createElement('div');
        div.className = type === 'success' ? 'text-[#39FF14]' : type === 'error' ? 'text-red-500' : 'text-white/30';
        div.textContent = `> ${message}`;
        statusLogs?.prepend(div);
    };

    const handleFile = (file: File) => {
        if (!file.type.startsWith('image/')) {
            log('Error: Invalid file format.', 'error');
            return;
        }

        const reader = new FileReader();
        reader.onload = (e) => {
            currentFileBase64 = (e.target?.result as string).split(',')[1];
            previewImg.src = e.target?.result as string;

            // Show Container
            previewContainer?.classList.remove('hidden');
            placeholder?.classList.add('hidden');
            analyzeBtn.disabled = false;

            log(`File loaded: ${file.name} [${(file.size / 1024).toFixed(1)} KB]`);

            // Clear previous canvas
            const ctx = overlayCanvas.getContext('2d');
            ctx?.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
        };
        reader.readAsDataURL(file);
    };

    dropZone?.addEventListener('click', () => fileInput.click());
    dropZone?.addEventListener('dragover', (e) => { e.preventDefault(); dropZone.classList.add('border-[#39FF14]'); });
    dropZone?.addEventListener('dragleave', () => dropZone.classList.remove('border-[#39FF14]'));
    dropZone?.addEventListener('drop', (e) => {
        e.preventDefault();
        dropZone.classList.remove('border-[#39FF14]');
        const file = e.dataTransfer?.files[0];
        if (file) handleFile(file);
    });

    fileInput.addEventListener('change', () => {
        const file = fileInput.files?.[0];
        if (file) handleFile(file);
    });

    const drawOverlays = (data: any) => {
        const ctx = overlayCanvas.getContext('2d');
        if (!ctx) return;

        overlayCanvas.width = previewImg.clientWidth;
        overlayCanvas.height = previewImg.clientHeight;

        const imgW = previewImg.naturalWidth;
        const imgH = previewImg.naturalHeight;
        const scaleX = overlayCanvas.width / imgW;
        const scaleY = overlayCanvas.height / imgH;

        // Draw Bounding Box
        if (data.bounding_box) {
            const [x1, y1, x2, y2] = data.bounding_box;
            ctx.strokeStyle = '#39FF14';
            ctx.lineWidth = 2;
            ctx.strokeRect(x1 * scaleX, y1 * scaleY, (x2 - x1) * scaleX, (y2 - y1) * scaleY);

            ctx.fillStyle = 'rgba(57, 255, 20, 0.1)';
            ctx.fillRect(x1 * scaleX, y1 * scaleY, (x2 - x1) * scaleX, (y2 - y1) * scaleY);

            ctx.font = '10px fira';
            ctx.fillStyle = '#39FF14';
            ctx.fillText('CORE_OBJECT_BOX', x1 * scaleX, (y1 * scaleY) - 5);
        }

        log('Visual overlays synchronized with mesh parameters.', 'success');
    };

    analyzeBtn.addEventListener('click', async () => {
        if (!currentFileBase64) return;

        analyzeBtn.disabled = true;
        scanner!.style.display = 'block';
        jsonOutput!.textContent = 'INITIATING ENGINE ANALYTICS...';
        log('Starting pixel-level analysis...');

        try {
            const prompt = `
            Ruolo: Sei il "Vision Engine" di un software di ricostruzione 3D (Image-to-Mesh). 
            Il tuo compito è analizzare le coordinate spaziali e le caratteristiche dei pixel di un'immagine per guidare un algoritmo di generazione mesh.

            Obiettivo: Trasforma l'input visivo in un set di parametri tecnici per una ricostruzione pixel-perfect. Non usare linguaggio descrittivo.

            Task Operativi:
            1. Segmentation Mask: Identifica i confini esatti dell'oggetto (foreground) rispetto allo sfondo.
            2. Keypoint Mapping: Individua i punti critici di curvatura.
            3. Depth Cues: Analizza le ombre e le sfumature per determinare la profondità relativa.
            4. Scale Calibration: Definisci il fattore di scala reale in base all'oggetto.

            Output richiesto (Solo JSON):
            {
              "object_id": "string",
              "bounding_box": [x1, y1, x2, y2],
              "topology_type": "string",
              "estimated_real_world_scale": {"unit": "cm", "dimensions": [W, D, H]},
              "pixel_fidelity_targets": ["string", "string"],
              "reconstruction_strategy": "string",
              "error_margin": "string"
            }
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    {
                        parts: [
                            { text: prompt },
                            { inlineData: { mimeType: "image/jpeg", data: currentFileBase64 } }
                        ]
                    }
                ],
                config: {
                    responseMimeType: "application/json"
                }
            });

            const resultText = response.text;
            const data = JSON.parse(resultText);

            jsonOutput!.textContent = JSON.stringify(data, null, 2);
            log('Analysis complete. 3D parameters generated.', 'success');

            if (data.error_margin) {
                log(`Warning: ${data.error_margin}`, 'error');
            }

            drawOverlays(data);

        } catch (error) {
            log('Critical Engine Failure: Analysis aborted.', 'error');
            jsonOutput!.textContent = 'ERROR: UNABLE TO PROCESS VISUAL BUFFER.';
            console.error(error);
        } finally {
            analyzeBtn.disabled = false;
            scanner!.style.display = 'none';
        }
    });
});

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus, Talent } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Star, Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, Info, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  // Traduzione stati ordine in Italiano
  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  // Gestione Download Forzato
  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
    setDownloadingId(requestId);
    try {
        const response = await fetch(videoUrl);
        if (!response.ok) throw new Error('Network response was not ok');

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${fileName}.mp4`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
    } catch (error) {
        console.error('Errore durante il download:', error);
        // Fallback: apri in nuova scheda se il fetch fallisce (es. CORS)
        window.open(videoUrl, '_blank');
    } finally {
        setDownloadingId(null);
    }
  };

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo!");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload.");
      } finally {
          setIsUploading(false);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className={`grid grid-cols-2 ${isTalent ? 'md:grid-cols-4' : 'md:grid-cols-3'} gap-4 mb-10`}>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            {/* SPESA TOTALE RIMOSSA PER FAN */}
            {isTalent && (
                <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                    <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                        <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">Guadagno Netto</p>
                        <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. {isTalent ? 'Appena arriverà un ordine lo vedrai qui!' : 'Inizia subito!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => {
                        const resolvedTalentName = req.talentName || talents[req.talentId] || 'Star di CiaoStar';
                        // Uso della mappa di traduzione
                        const statusItalian = statusMap[req.status] || req.status;

                        return (
                            <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                                req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                            }`}>
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                        req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                        req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                        req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                        req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                        'bg-gray-100 text-slate-400'
                                    }`}>{statusItalian}</div>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8).toUpperCase()}</span>
                                </div>

                                <div className="flex justify-between items-end mb-6">
                                    <div>
                                        <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                            {isTalent ? `Per: ${req.recipientName}` : `Da: ${resolvedTalentName}`}
                                        </h3>
                                        <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                    </div>
                                    <div className="text-right">
                                        {/* ETICHETTA CAMBIATA IN PREZZO */}
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">PREZZO</p>
                                        <p className="text-xl font-black text-slate-900">
                                            €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                        </p>
                                        {isTalent && (
                                            <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                                <ArrowDownRight className="w-2.5 h-2.5" />
                                                Lordo €{req.pricePaid.toFixed(2)}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative group">
                                    <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                    "{req.instructions}"
                                </div>

                                {/* Azioni Talent */}
                                {isTalent && (
                                    <div className="space-y-4">
                                        {req.status === RequestStatus.PENDING && (
                                            <div className="grid grid-cols-2 gap-3">
                                                <button 
                                                    onClick={() => setRejectingId(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                                >
                                                    <X className="w-4 h-4" /> Rifiuta
                                                </button>
                                                <button 
                                                    onClick={() => handleAccept(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                                >
                                                    <Check className="w-4 h-4" /> Accetta
                                                </button>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.ACCEPTED && (
                                            <div>
                                                {uploadingId === req.id ? (
                                                    <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6 animate-in fade-in slide-in-from-top-4">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Upload Video</h4>
                                                            <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                        </div>

                                                        <div className="space-y-4">
                                                            <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                                <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                                <span className="text-sm font-bold text-slate-500">
                                                                    {uploadFile ? uploadFile.name : 'Seleziona file video (MP4/MOV)'}
                                                                </span>
                                                                <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                            </label>

                                                            <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                                <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                    <ShieldCheck className="w-3 h-3" /> Controllo Qualità
                                                                </p>
                                                                {[
                                                                    { key: 'nameSaid', label: 'Ho pronunciato il nome' },
                                                                    { key: 'durationOk', label: 'Durata almeno 20s' },
                                                                    { key: 'audioClear', label: 'Audio chiaro' }
                                                                ].map(item => (
                                                                    <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                        <input 
                                                                            type="checkbox" 
                                                                            checked={(qualityCheck as any)[item.key]} 
                                                                            onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                            className="sr-only"
                                                                        />
                                                                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                            (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                        }`}>
                                                                            {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                        </div>
                                                                        <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                    </label>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        <button 
                                                            disabled={isUploading || !uploadFile}
                                                            onClick={() => handleUploadSubmit(req.id)}
                                                            className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                        >
                                                            {isUploading ? (
                                                                <><Loader2 className="animate-spin w-4 h-4" /> Caricamento...</>
                                                            ) : (
                                                                <><Video className="w-4 h-4" /> Invia al Fan</>
                                                            )}
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button 
                                                        onClick={() => setUploadingId(req.id)}
                                                        className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-emerald-500 text-white font-bold text-sm hover:bg-emerald-600 shadow-lg shadow-emerald-50 transition-all"
                                                    >
                                                        <Upload className="w-4 h-4" /> Carica Video Completato
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Visualizzazione Video o Placeholder */}
                                {req.videoUrl ? (
                                    <div className="space-y-4">
                                        <div className="rounded-2xl overflow-hidden shadow-inner bg-black aspect-video relative group">
                                            <VideoPlayer src={req.videoUrl} canDownload={false} />
                                        </div>
                                        {/* AZIONE DI DOWNLOAD FORZATO PER IL FAN */}
                                        {!isTalent && (
                                            <button 
                                                disabled={downloadingId === req.id}
                                                onClick={() => handleDownload(req.videoUrl!, `CiaoStar_${resolvedTalentName}`, req.id)}
                                                className="btn-primary w-full py-4 disabled:opacity-70 flex items-center justify-center gap-2"
                                            >
                                                {downloadingId === req.id ? (
                                                    <><Loader2 className="animate-spin w-4 h-4" /> Preparazione download...</>
                                                ) : (
                                                    <><Download className="w-4 h-4" /> Scarica il tuo regalo</>
                                                )}
                                            </button>
                                        )}
                                    </div>
                                ) : (
                                    (!isTalent || (req.status !== RequestStatus.PENDING && req.status !== RequestStatus.ACCEPTED)) ? (
                                        <div className={`py-12 flex flex-col items-center justify-center rounded-2xl border-2 border-dashed ${
                                            req.status === RequestStatus.REJECTED ? 'bg-red-50/30 border-red-100 text-red-400' : 'bg-gray-50 border-gray-100 text-slate-400'
                                        }`}>
                                            {req.status === RequestStatus.REJECTED ? (
                                                <div className="text-center px-6 w-full">
                                                    <AlertCircle className="w-10 h-10 mb-3 mx-auto opacity-40 text-red-400" />
                                                    <span className="block text-sm font-black uppercase tracking-widest mb-4 text-red-600">Richiesta Rifiutata</span>

                                                    {req.rejectionReason && (
                                                        <div className="bg-white p-5 rounded-2xl shadow-sm border border-red-100 max-w-sm mx-auto text-left relative overflow-hidden">
                                                            <div className="absolute top-0 left-0 w-1 h-full bg-red-500"></div>
                                                            <p className="text-[10px] font-black text-red-500 uppercase mb-2 flex items-center gap-2">
                                                                <MessageSquare className="w-3.5 h-3.5" /> Motivo:
                                                            </p>
                                                            <p className="text-sm font-bold text-red-900 leading-relaxed italic">
                                                                "{req.rejectionReason}"
                                                            </p>
                                                        </div>
                                                    )}
                                                    {!isTalent && (
                                                        <div className="mt-6 flex items-center justify-center gap-2 text-[10px] font-black text-slate-400 bg-white/50 px-4 py-2 rounded-full border border-gray-100 w-fit mx-auto">
                                                            <CornerUpLeft className="w-3.5 h-3.5" /> Fondi rimborsati integralmente
                                                        </div>
                                                    )}
                                                </div>
                                            ) : (
                                                <>
                                                    <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                                    <span className="text-sm font-bold uppercase tracking-widest text-slate-300">
                                                        In attesa del video...
                                                    </span>
                                                </>
                                            )}
                                        </div>
                                    ) : null
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>

        {/* MODALE RIFIUTO (Talent) */}
        {rejectingId && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
                    <div className="p-8 border-b border-gray-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-red-500 p-2 rounded-xl">
                                <AlertCircle className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="font-extrabold text-slate-900 uppercase tracking-tight">Motiva il rifiuto</h3>
                        </div>
                        <button onClick={() => !isRejecting && setRejectingId(null)} className="text-slate-400 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                    </div>

                    <div className="p-8">
                        <p className="text-sm text-slate-500 font-medium mb-6">Perché rifiuti? Il Fan vedrà questo motivo.</p>
                        <textarea 
                            className="input-main min-h-[100px] mb-6"
                            placeholder="Es. Richiesta inappropriata..."
                            value={rejectionReason}
                            onChange={(e) => setRejectionReason(e.target.value)}
                            required
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setRejectingId(null)} className="btn-secondary flex-1">Annulla</button>
                            <button onClick={submitRejection} className="bg-red-600 text-white flex-1 py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-red-700 disabled:opacity-50">
                                {isRejecting ? <Loader2 className="animate-spin mx-auto w-4 h-4" /> : 'Conferma Rifiuto'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  // Traduzione stati ordine in Italiano
  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  // Gestione Download Forzato (Fetch -> Blob -> Link Download)
  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
    setDownloadingId(requestId);
    try {
        const response = await fetch(videoUrl);
        if (!response.ok) throw new Error('Download fallito');

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${fileName}.mp4`; // Forza l'estensione mp4
        document.body.appendChild(link);
        link.click();

        // Cleanup
        document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
    } catch (error) {
        console.error('Errore durante il download:', error);
        // Fallback: apre in nuova finestra se il fetch fallisce (es. per policy CORS rigide)
        window.open(videoUrl, '_blank');
    } finally {
        setDownloadingId(null);
    }
  };

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo!");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload.");
      } finally {
          setIsUploading(false);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className={`grid grid-cols-2 ${isTalent ? 'md:grid-cols-4' : 'md:grid-cols-3'} gap-4 mb-10`}>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            {isTalent && (
                <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                    <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                        <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">Guadagno Netto</p>
                        <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. {isTalent ? 'Appena arriverà un ordine lo vedrai qui!' : 'Inizia subito!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => {
                        const resolvedTalentName = req.talentName || talents[req.talentId] || 'Star di CiaoStar';
                        const statusItalian = statusMap[req.status] || req.status;

                        return (
                            <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                                req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                            }`}>
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                        req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                        req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                        req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                        req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                        'bg-gray-100 text-slate-400'
                                    }`}>{statusItalian}</div>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8).toUpperCase()}</span>
                                </div>

                                <div className="flex justify-between items-end mb-6">
                                    <div>
                                        <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                            {isTalent ? `Per: ${req.recipientName}` : `Da: ${resolvedTalentName}`}
                                        </h3>
                                        <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">PREZZO</p>
                                        <p className="text-xl font-black text-slate-900">
                                            €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                        </p>
                                        {isTalent && (
                                            <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                                <ArrowDownRight className="w-2.5 h-2.5" />
                                                Lordo €{req.pricePaid.toFixed(2)}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative group">
                                    <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                    "{req.instructions}"
                                </div>

                                {/* Azioni Talent */}
                                {isTalent && (
                                    <div className="space-y-4">
                                        {req.status === RequestStatus.PENDING && (
                                            <div className="grid grid-cols-2 gap-3">
                                                <button 
                                                    onClick={() => setRejectingId(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                                >
                                                    <X className="w-4 h-4" /> Rifiuta
                                                </button>
                                                <button 
                                                    onClick={() => handleAccept(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                                >
                                                    <Check className="w-4 h-4" /> Accetta
                                                </button>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.ACCEPTED && (
                                            <div>
                                                {uploadingId === req.id ? (
                                                    <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6 animate-in fade-in slide-in-from-top-4">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Upload Video</h4>
                                                            <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                        </div>

                                                        <div className="space-y-4">
                                                            <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                                <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                                <span className="text-sm font-bold text-slate-500">
                                                                    {uploadFile ? uploadFile.name : 'Seleziona file video (MP4/MOV)'}
                                                                </span>
                                                                <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                            </label>

                                                            <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                                <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                    <ShieldCheck className="w-3 h-3" /> Controllo Qualità
                                                                </p>
                                                                {[
                                                                    { key: 'nameSaid', label: 'Ho pronunciato il nome' },
                                                                    { key: 'durationOk', label: 'Durata almeno 20s' },
                                                                    { key: 'audioClear', label: 'Audio chiaro' }
                                                                ].map(item => (
                                                                    <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                        <input 
                                                                            type="checkbox" 
                                                                            checked={(qualityCheck as any)[item.key]} 
                                                                            onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                            className="sr-only"
                                                                        />
                                                                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                            (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                        }`}>
                                                                            {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                        </div>
                                                                        <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                    </label>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        <button 
                                                            disabled={isUploading || !uploadFile}
                                                            onClick={() => handleUploadSubmit(req.id)}
                                                            className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                        >
                                                            {isUploading ? (
                                                                <><Loader2 className="animate-spin w-4 h-4" /> Caricamento...</>
                                                            ) : (
                                                                <><Video className="w-4 h-4" /> Invia al Fan</>
                                                            )}
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button 
                                                        onClick={() => setUploadingId(req.id)}
                                                        className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-emerald-500 text-white font-bold text-sm hover:bg-emerald-600 shadow-lg shadow-emerald-50 transition-all"
                                                    >
                                                        <Upload className="w-4 h-4" /> Carica Video Completato
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Visualizzazione Video o Placeholder */}
                                {req.videoUrl ? (
                                    <div className="space-y-4">
                                        <div className="rounded-2xl overflow-hidden shadow-inner bg-black aspect-video relative group">
                                            <VideoPlayer src={req.videoUrl} canDownload={false} />
                                        </div>
                                        {!isTalent && (
                                            <button 
                                                disabled={downloadingId === req.id}
                                                onClick={() => handleDownload(req.videoUrl!, `CiaoStar_${resolvedTalentName}`, req.id)}
                                                className="btn-primary w-full py-4 disabled:opacity-70 flex items-center justify-center gap-2"
                                            >
                                                {downloadingId === req.id ? (
                                                    <><Loader2 className="animate-spin w-4 h-4" /> Preparazione download...</>
                                                ) : (
                                                    <><Download className="w-4 h-4" /> Scarica il tuo regalo</>
                                                )}
                                            </button>
                                        )}
                                    </div>
                                ) : (
                                    (!isTalent || (req.status !== RequestStatus.PENDING && req.status !== RequestStatus.ACCEPTED)) ? (
                                        <div className={`py-12 flex flex-col items-center justify-center rounded-2xl border-2 border-dashed ${
                                            req.status === RequestStatus.REJECTED ? 'bg-red-50/30 border-red-100 text-red-400' : 'bg-gray-50 border-gray-100 text-slate-400'
                                        }`}>
                                            {req.status === RequestStatus.REJECTED ? (
                                                <div className="text-center px-6 w-full">
                                                    <AlertCircle className="w-10 h-10 mb-3 mx-auto opacity-40 text-red-400" />
                                                    <span className="block text-sm font-black uppercase tracking-widest mb-4 text-red-600">Richiesta Rifiutata</span>

                                                    {req.rejectionReason && (
                                                        <div className="bg-white p-5 rounded-2xl shadow-sm border border-red-100 max-w-sm mx-auto text-left relative overflow-hidden">
                                                            <div className="absolute top-0 left-0 w-1 h-full bg-red-500"></div>
                                                            <p className="text-[10px] font-black text-red-500 uppercase mb-2 flex items-center gap-2">
                                                                <MessageSquare className="w-3.5 h-3.5" /> Motivo:
                                                            </p>
                                                            <p className="text-sm font-bold text-red-900 leading-relaxed italic">
                                                                "{req.rejectionReason}"
                                                            </p>
                                                        </div>
                                                    )}
                                                    {!isTalent && (
                                                        <div className="mt-6 flex items-center justify-center gap-2 text-[10px] font-black text-slate-400 bg-white/50 px-4 py-2 rounded-full border border-gray-100 w-fit mx-auto">
                                                            <CornerUpLeft className="w-3.5 h-3.5" /> Fondi rimborsati integralmente
                                                        </div>
                                                    )}
                                                </div>
                                            ) : (
                                                <>
                                                    <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                                    <span className="text-sm font-bold uppercase tracking-widest text-slate-300">
                                                        In attesa del video...
                                                    </span>
                                                </>
                                            )}
                                        </div>
                                    ) : null
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>

        {/* MODALE RIFIUTO (Talent) */}
        {rejectingId && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
                    <div className="p-8 border-b border-gray-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-red-500 p-2 rounded-xl">
                                <AlertCircle className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="font-extrabold text-slate-900 uppercase tracking-tight">Motiva il rifiuto</h3>
                        </div>
                        <button onClick={() => !isRejecting && setRejectingId(null)} className="text-slate-400 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                    </div>

                    <div className="p-8">
                        <p className="text-sm text-slate-500 font-medium mb-6">Perché rifiuti? Il Fan vedrà questo motivo.</p>
                        <textarea 
                            className="input-main min-h-[100px] mb-6"
                            placeholder="Es. Richiesta inappropriata..."
                            value={rejectionReason}
                            onChange={(e) => setRejectionReason(e.target.value)}
                            required
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setRejectingId(null)} className="btn-secondary flex-1">Annulla</button>
                            <button onClick={submitRejection} className="bg-red-600 text-white flex-1 py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-red-700 disabled:opacity-50">
                                {isRejecting ? <Loader2 className="animate-spin mx-auto w-4 h-4" /> : 'Conferma Rifiuto'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus, Talent } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Star, Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, Info, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  // Traduzione stati ordine
  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo!");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload.");
      } finally {
          setIsUploading(false);
      }
  };

  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
      setDownloadingId(requestId);
      try {
          // Tentativo di download tramite Blob per forzare il salvataggio (richiede CORS configurato su Firebase)
          const response = await fetch(videoUrl);
          if (!response.ok) throw new Error('Download via fetch fallito (probabile CORS)');

          const blob = await response.blob();
          const url = window.URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = `${fileName}.mp4`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          window.URL.revokeObjectURL(url);
      } catch (error) {
          // Se fallisce (CORS), apriamo semplicemente in una nuova scheda
          // Questo evita l'alert fastidioso e permette comunque all'utente di vedere/salvare il video
          console.warn('Download forzato fallito, fallback a apertura link diretto:', error);
          window.open(videoUrl, '_blank');
      } finally {
          setDownloadingId(null);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className={`grid grid-cols-2 ${isTalent ? 'md:grid-cols-4' : 'md:grid-cols-3'} gap-4 mb-10`}>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            {isTalent && (
                <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                    <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                        <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">Guadagno Netto</p>
                        <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. {isTalent ? 'Appena arriverà un ordine lo vedrai qui!' : 'Inizia subito!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => {
                        const resolvedTalentName = req.talentName || talents[req.talentId] || 'Star di CiaoStar';
                        const statusItalian = statusMap[req.status] || req.status;

                        return (
                            <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                                req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                            }`}>
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                        req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                        req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                        req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                        req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                        'bg-gray-100 text-slate-400'
                                    }`}>{statusItalian}</div>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8).toUpperCase()}</span>
                                </div>

                                <div className="flex justify-between items-end mb-6">
                                    <div>
                                        <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                            {isTalent ? `Per: ${req.recipientName}` : `Da: ${resolvedTalentName}`}
                                        </h3>
                                        <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">PREZZO</p>
                                        <p className="text-xl font-black text-slate-900">
                                            €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                        </p>
                                        {isTalent && (
                                            <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                                <ArrowDownRight className="w-2.5 h-2.5" />
                                                Lordo €{req.pricePaid.toFixed(2)}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative group">
                                    <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                    "{req.instructions}"
                                </div>

                                {/* Azioni Talent */}
                                {isTalent && (
                                    <div className="space-y-4">
                                        {req.status === RequestStatus.PENDING && (
                                            <div className="grid grid-cols-2 gap-3">
                                                <button 
                                                    onClick={() => setRejectingId(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                                >
                                                    <X className="w-4 h-4" /> Rifiuta
                                                </button>
                                                <button 
                                                    onClick={() => handleAccept(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                                >
                                                    <Check className="w-4 h-4" /> Accetta
                                                </button>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.REJECTED && req.rejectionReason && (
                                            <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex gap-3">
                                                <X className="w-4 h-4 text-red-600 mt-1" />
                                                <div>
                                                    <p className="text-[9px] font-black text-red-400 uppercase">Hai rifiutato per:</p>
                                                    <p className="text-xs font-bold text-red-900">"{req.rejectionReason}"</p>
                                                </div>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.ACCEPTED && (
                                            <div>
                                                {uploadingId === req.id ? (
                                                    <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6 animate-in fade-in slide-in-from-top-4">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Upload Video</h4>
                                                            <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                        </div>

                                                        <div className="space-y-4">
                                                            <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                                <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                                <span className="text-sm font-bold text-slate-500">
                                                                    {uploadFile ? uploadFile.name : 'Seleziona file video (MP4/MOV)'}
                                                                </span>
                                                                <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                            </label>

                                                            <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                                <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                    <ShieldCheck className="w-3 h-3" /> Controllo Qualità
                                                                </p>
                                                                {[
                                                                    { key: 'nameSaid', label: 'Ho pronunciato il nome' },
                                                                    { key: 'durationOk', label: 'Durata almeno 20s' },
                                                                    { key: 'audioClear', label: 'Audio chiaro' }
                                                                ].map(item => (
                                                                    <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                        <input 
                                                                            type="checkbox" 
                                                                            checked={(qualityCheck as any)[item.key]} 
                                                                            onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                            className="sr-only"
                                                                        />
                                                                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                            (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                        }`}>
                                                                            {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                        </div>
                                                                        <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                    </label>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        <button 
                                                            disabled={isUploading || !uploadFile}
                                                            onClick={() => handleUploadSubmit(req.id)}
                                                            className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                        >
                                                            {isUploading ? (
                                                                <><Loader2 className="animate-spin w-4 h-4" /> Caricamento...</>
                                                            ) : (
                                                                <><Video className="w-4 h-4" /> Invia al Fan</>
                                                            )}
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button 
                                                        onClick={() => setUploadingId(req.id)}
                                                        className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-emerald-500 text-white font-bold text-sm hover:bg-emerald-600 shadow-lg shadow-emerald-50 transition-all"
                                                    >
                                                        <Upload className="w-4 h-4" /> Carica Video Completato
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Visualizzazione Video o Placeholder */}
                                {req.videoUrl ? (
                                    <div className="space-y-4">
                                        <div className="rounded-2xl overflow-hidden shadow-inner bg-black aspect-video relative group">
                                            <VideoPlayer src={req.videoUrl} canDownload={false} />
                                        </div>
                                        {!isTalent && (
                                            <button 
                                                disabled={downloadingId === req.id}
                                                onClick={() => handleDownload(req.videoUrl!, `CiaoStar_${resolvedTalentName}`, req.id)}
                                                className="btn-primary w-full py-4 disabled:opacity-70"
                                            >
                                                {downloadingId === req.id ? (
                                                    <><Loader2 className="animate-spin w-4 h-4" /> Preparazione download...</>
                                                ) : (
                                                    <><Download className="w-4 h-4" /> Scarica il tuo regalo</>
                                                )}
                                            </button>
                                        )}
                                    </div>
                                ) : (
                                    (!isTalent || (req.status !== RequestStatus.PENDING && req.status !== RequestStatus.ACCEPTED)) ? (
                                        <div className={`py-12 flex flex-col items-center justify-center rounded-2xl border-2 border-dashed ${
                                            req.status === RequestStatus.REJECTED ? 'bg-red-50/30 border-red-100 text-red-400' : 'bg-gray-50 border-gray-100 text-slate-400'
                                        }`}>
                                            {req.status === RequestStatus.REJECTED ? (
                                                <div className="text-center px-6 w-full">
                                                    <AlertCircle className="w-10 h-10 mb-3 mx-auto opacity-40 text-red-400" />
                                                    <span className="block text-sm font-black uppercase tracking-widest mb-4 text-red-600">Richiesta Rifiutata</span>

                                                    {req.rejectionReason && (
                                                        <div className="bg-white p-5 rounded-2xl shadow-sm border border-red-100 max-w-sm mx-auto text-left relative overflow-hidden">
                                                            <div className="absolute top-0 left-0 w-1 h-full bg-red-500"></div>
                                                            <p className="text-[10px] font-black text-red-500 uppercase mb-2 flex items-center gap-2">
                                                                <MessageSquare className="w-3.5 h-3.5" /> Motivo:
                                                            </p>
                                                            <p className="text-sm font-bold text-red-900 leading-relaxed italic">
                                                                "{req.rejectionReason}"
                                                            </p>
                                                        </div>
                                                    )}
                                                    {!isTalent && (
                                                        <div className="mt-6 flex items-center justify-center gap-2 text-[10px] font-black text-slate-400 bg-white/50 px-4 py-2 rounded-full border border-gray-100 w-fit mx-auto">
                                                            <CornerUpLeft className="w-3.5 h-3.5" /> Fondi rimborsati integralmente
                                                        </div>
                                                    )}
                                                </div>
                                            ) : (
                                                <>
                                                    <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                                    <span className="text-sm font-bold uppercase tracking-widest text-slate-300">
                                                        In attesa del video...
                                                    </span>
                                                </>
                                            )}
                                        </div>
                                    ) : null
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>

        {/* MODALE RIFIUTO (Talent) */}
        {rejectingId && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
                    <div className="p-8 border-b border-gray-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-red-500 p-2 rounded-xl">
                                <AlertCircle className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="font-extrabold text-slate-900 uppercase tracking-tight">Motiva il rifiuto</h3>
                        </div>
                        <button onClick={() => !isRejecting && setRejectingId(null)} className="text-slate-400 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                    </div>

                    <div className="p-8">
                        <p className="text-sm text-slate-500 font-medium mb-6">Perché rifiuti? Il Fan vedrà questo motivo.</p>
                        <textarea 
                            className="input-main min-h-[100px] mb-6"
                            placeholder="Es. Richiesta inappropriata..."
                            value={rejectionReason}
                            onChange={(e) => setRejectionReason(e.target.value)}
                            required
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setRejectingId(null)} className="btn-secondary flex-1">Annulla</button>
                            <button onClick={submitRejection} className="bg-red-600 text-white flex-1 py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-red-700 disabled:opacity-50">
                                {isRejecting ? <Loader2 className="animate-spin mx-auto w-4 h-4" /> : 'Conferma Rifiuto'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus, Talent } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Wallet, Star, Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, Info, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  // Traduzione stati ordine in Italiano
  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo!");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload.");
      } finally {
          setIsUploading(false);
      }
  };

  // Funzione di Download Definitiva
  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
      setDownloadingId(requestId);
      const cleanFileName = fileName.replace(/[^a-z0-9]/gi, '_').toLowerCase();

      try {
          // Tentativo 1: Fetch come Blob (Richiede CORS su Firebase)
          const response = await fetch(videoUrl, { method: 'GET' });
          if (!response.ok) throw new Error('CORS o Network error');

          const blob = await response.blob();
          const url = window.URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.setAttribute('download', `${cleanFileName}.mp4`);
          document.body.appendChild(link);
          link.click();

          // Cleanup
          setTimeout(() => {
              document.body.removeChild(link);
              window.URL.revokeObjectURL(url);
          }, 200);
      } catch (error) {
          console.warn('Download forzato fallito, fallback a link diretto con attributo download.');
          // Tentativo 2: Link diretto con attributo download (alcuni browser lo forzano comunque)
          const link = document.createElement('a');
          link.href = videoUrl;
          link.target = '_blank';
          link.setAttribute('download', `${cleanFileName}.mp4`);
          link.click();
      } finally {
          setDownloadingId(null);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Caricamento ordini...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  const isTalent = user.role === UserRole.TALENT;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni netti.' : 'Gestisci i tuoi video messaggi e lo stato delle richieste.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className={`grid grid-cols-2 ${isTalent ? 'md:grid-cols-4' : 'md:grid-cols-3'} gap-4 mb-10`}>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            {isTalent && (
                <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                    <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                        <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">Guadagno Netto</p>
                        <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Ordini da elaborare' : 'Le tue richieste'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Ancora nessun video. {isTalent ? 'Appena arriverà un ordine lo vedrai qui!' : 'Inizia subito!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => {
                        const resolvedTalentName = req.talentName || talents[req.talentId] || 'Star di CiaoStar';
                        const statusItalian = statusMap[req.status] || req.status;

                        return (
                            <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                                req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                            }`}>
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                        req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                        req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                        req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                        req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                        'bg-gray-100 text-slate-400'
                                    }`}>{statusItalian}</div>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase">ID #{req.id.substring(0,8).toUpperCase()}</span>
                                </div>

                                <div className="flex justify-between items-end mb-6">
                                    <div>
                                        <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                            {isTalent ? `Per: ${req.recipientName}` : `Da: ${resolvedTalentName}`}
                                        </h3>
                                        <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">PREZZO</p>
                                        <p className="text-xl font-black text-slate-900">
                                            €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                        </p>
                                        {isTalent && (
                                            <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                                <ArrowDownRight className="w-2.5 h-2.5" />
                                                Lordo €{req.pricePaid.toFixed(2)}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative group">
                                    <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                    "{req.instructions}"
                                </div>

                                {/* Azioni Talent */}
                                {isTalent && (
                                    <div className="space-y-4">
                                        {req.status === RequestStatus.PENDING && (
                                            <div className="grid grid-cols-2 gap-3">
                                                <button 
                                                    onClick={() => setRejectingId(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                                >
                                                    <X className="w-4 h-4" /> Rifiuta
                                                </button>
                                                <button 
                                                    onClick={() => handleAccept(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                                >
                                                    <Check className="w-4 h-4" /> Accetta
                                                </button>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.ACCEPTED && (
                                            <div>
                                                {uploadingId === req.id ? (
                                                    <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6 animate-in fade-in slide-in-from-top-4">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Upload Video</h4>
                                                            <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                        </div>

                                                        <div className="space-y-4">
                                                            <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                                <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                                <span className="text-sm font-bold text-slate-500">
                                                                    {uploadFile ? uploadFile.name : 'Seleziona file video (MP4/MOV)'}
                                                                </span>
                                                                <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                            </label>

                                                            <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                                <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                    <ShieldCheck className="w-3 h-3" /> Controllo Qualità
                                                                </p>
                                                                {[
                                                                    { key: 'nameSaid', label: 'Ho pronunciato il nome' },
                                                                    { key: 'durationOk', label: 'Durata almeno 20s' },
                                                                    { key: 'audioClear', label: 'Audio chiaro' }
                                                                ].map(item => (
                                                                    <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                        <input 
                                                                            type="checkbox" 
                                                                            checked={(qualityCheck as any)[item.key]} 
                                                                            onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                            className="sr-only"
                                                                        />
                                                                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                            (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                        }`}>
                                                                            {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                        </div>
                                                                        <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                    </label>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        <button 
                                                            disabled={isUploading || !uploadFile}
                                                            onClick={() => handleUploadSubmit(req.id)}
                                                            className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                        >
                                                            {isUploading ? (
                                                                <><Loader2 className="animate-spin w-4 h-4" /> Caricamento...</>
                                                            ) : (
                                                                <><Video className="w-4 h-4" /> Invia al Fan</>
                                                            )}
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button 
                                                        onClick={() => setUploadingId(req.id)}
                                                        className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-emerald-500 text-white font-bold text-sm hover:bg-emerald-600 shadow-lg shadow-emerald-50 transition-all"
                                                    >
                                                        <Upload className="w-4 h-4" /> Carica Video Completato
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Visualizzazione Video o Placeholder */}
                                {req.videoUrl ? (
                                    <div className="space-y-4">
                                        <div className="rounded-2xl overflow-hidden shadow-inner bg-black aspect-video relative group">
                                            <VideoPlayer src={req.videoUrl} canDownload={false} />
                                        </div>
                                        {!isTalent && (
                                            <button 
                                                disabled={downloadingId === req.id}
                                                onClick={() => handleDownload(req.videoUrl!, `ciaostar_video_${resolvedTalentName}`, req.id)}
                                                className="btn-primary w-full py-4 disabled:opacity-70 flex items-center justify-center gap-2"
                                            >
                                                {downloadingId === req.id ? (
                                                    <><Loader2 className="animate-spin w-4 h-4" /> Preparazione download...</>
                                                ) : (
                                                    <><Download className="w-4 h-4" /> Scarica il tuo regalo</>
                                                )}
                                            </button>
                                        )}
                                    </div>
                                ) : (
                                    (!isTalent || (req.status !== RequestStatus.PENDING && req.status !== RequestStatus.ACCEPTED)) ? (
                                        <div className={`py-12 flex flex-col items-center justify-center rounded-2xl border-2 border-dashed ${
                                            req.status === RequestStatus.REJECTED ? 'bg-red-50/30 border-red-100 text-red-400' : 'bg-gray-50 border-gray-100 text-slate-400'
                                        }`}>
                                            {req.status === RequestStatus.REJECTED ? (
                                                <div className="text-center px-6 w-full">
                                                    <AlertCircle className="w-10 h-10 mb-3 mx-auto opacity-40 text-red-400" />
                                                    <span className="block text-sm font-black uppercase tracking-widest mb-4 text-red-600">Richiesta Rifiutata</span>

                                                    {req.rejectionReason && (
                                                        <div className="bg-white p-5 rounded-2xl shadow-sm border border-red-100 max-w-sm mx-auto text-left relative overflow-hidden">
                                                            <div className="absolute top-0 left-0 w-1 h-full bg-red-500"></div>
                                                            <p className="text-[10px] font-black text-red-500 uppercase mb-2 flex items-center gap-2">
                                                                <MessageSquare className="w-3.5 h-3.5" /> Motivo:
                                                            </p>
                                                            <p className="text-sm font-bold text-red-900 leading-relaxed italic">
                                                                "{req.rejectionReason}"
                                                            </p>
                                                        </div>
                                                    )}
                                                    {!isTalent && (
                                                        <div className="mt-6 flex items-center justify-center gap-2 text-[10px] font-black text-slate-400 bg-white/50 px-4 py-2 rounded-full border border-gray-100 w-fit mx-auto">
                                                            <CornerUpLeft className="w-3.5 h-3.5" /> Fondi rimborsati integralmente
                                                        </div>
                                                    )}
                                                </div>
                                            ) : (
                                                <>
                                                    <PlayCircle className="w-10 h-10 mb-3 opacity-20" />
                                                    <span className="text-sm font-bold uppercase tracking-widest text-slate-300">
                                                        In attesa del video...
                                                    </span>
                                                </>
                                            )}
                                        </div>
                                    ) : null
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>

        {/* MODALE RIFIUTO (Talent) */}
        {rejectingId && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
                    <div className="p-8 border-b border-gray-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="bg-red-500 p-2 rounded-xl">
                                <AlertCircle className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="font-extrabold text-slate-900 uppercase tracking-tight">Motiva il rifiuto</h3>
                        </div>
                        <button onClick={() => !isRejecting && setRejectingId(null)} className="text-slate-400 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                    </div>

                    <div className="p-8">
                        <p className="text-sm text-slate-500 font-medium mb-6">Perché rifiuti? Il Fan vedrà questo motivo.</p>
                        <textarea 
                            className="input-main min-h-[100px] mb-6"
                            placeholder="Es. Richiesta inappropriata..."
                            value={rejectionReason}
                            onChange={(e) => setRejectionReason(e.target.value)}
                            required
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setRejectingId(null)} className="btn-secondary flex-1">Annulla</button>
                            <button onClick={submitRejection} className="bg-red-600 text-white flex-1 py-4 rounded-2xl font-black uppercase shadow-xl hover:bg-red-700 disabled:opacity-50">
                                {isRejecting ? <Loader2 className="animate-spin mx-auto w-4 h-4" /> : 'Conferma Rifiuto'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
    setDownloadingId(requestId);
    try {
        // Tentativo di download forzato via Blob
        const response = await fetch(videoUrl);
        if (!response.ok) throw new Error('CORS limit');

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${fileName.replace(/\s+/g, '_')}.mp4`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
    } catch (error) {
        console.warn('Download forzato fallito (CORS). Fallback al link diretto.');
        // Fallback: apriamo il link diretto che permette il "Salva con nome" manuale
        window.open(videoUrl, '_blank');
    } finally {
        setDownloadingId(null);
    }
  };

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
          setUploadingId(null);
          setUploadFile(null);
          setQualityCheck({ nameSaid: false, durationOk: false, audioClear: false });
          alert("Video caricato con successo!");
          refresh();
      } catch (e: any) {
          console.error(e);
          alert("Errore durante l'upload.");
      } finally {
          setIsUploading(false);
      }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <Loader2 className="animate-spin w-10 h-10 text-indigo-600 mb-4" />
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Sincronizzazione Dashboard...</p>
    </div>
  );

  const completedRequests = requests.filter(r => r.status === RequestStatus.COMPLETED);
  const isTalent = user.role === UserRole.TALENT;

  const stats = {
      total: requests.length,
      pending: requests.filter(r => r.status === RequestStatus.PENDING).length,
      completed: completedRequests.length,
      grossEarnings: completedRequests.reduce((acc, r) => acc + r.pricePaid, 0),
      totalFees: completedRequests.reduce((acc, r) => acc + (r.applicationFee || 0), 0),
      netEarnings: completedRequests.reduce((acc, r) => acc + (r.pricePaid - (r.applicationFee || 0)), 0)
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
                <h1 className="text-3xl font-extrabold text-slate-900 mb-1">
                    {isTalent ? 'Console Star' : 'La tua Dashboard'}
                </h1>
                <p className="text-slate-500 font-medium">
                    {isTalent ? 'Gestisci le tue richieste e monitora i tuoi guadagni.' : 'Qui trovi tutti i tuoi video messaggi e lo stato dei tuoi ordini.'}
                </p>
            </div>
            <button onClick={refresh} className="btn-secondary">
                <RefreshCw className="w-4 h-4 mr-2" /> Aggiorna
            </button>
        </div>

        {/* Stats Grid */}
        <div className={`grid grid-cols-2 ${isTalent ? 'md:grid-cols-4' : 'md:grid-cols-3'} gap-4 mb-10`}>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Package className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Ordini Totali</p>
                <p className="text-2xl font-black text-slate-900">{stats.total}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-amber-50 text-amber-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><Clock className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">In attesa</p>
                <p className="text-2xl font-black text-slate-900">{stats.pending}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                <div className="bg-emerald-50 text-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center mb-4"><CheckCircle className="w-5 h-5" /></div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Completati</p>
                <p className="text-2xl font-black text-slate-900">{stats.completed}</p>
            </div>

            {isTalent && (
                <div className="bg-indigo-600 p-6 rounded-2xl shadow-xl shadow-indigo-100 text-white flex flex-col justify-between relative overflow-hidden group">
                    <TrendingUp className="absolute -bottom-2 -right-2 w-16 h-16 text-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                        <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-wider mb-1">Guadagno Netto</p>
                        <p className="text-3xl font-black">€{stats.netEarnings.toFixed(2)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-white/10 text-[9px] font-bold uppercase tracking-widest text-indigo-100">
                        <div className="flex justify-between">
                            <span>Lordo:</span>
                            <span>€{stats.grossEarnings.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mt-1 text-pink-300">
                            <span>Commissioni:</span>
                            <span>-€{stats.totalFees.toFixed(2)}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Requests List */}
        <div className="space-y-6">
            <h2 className="text-xl font-extrabold text-slate-900">
                {isTalent ? 'Richieste da gestire' : 'I tuoi video messaggi'}
            </h2>

            {requests.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border border-gray-100">
                    <Gift className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-400 font-bold">Nessun ordine trovato. {isTalent ? 'Appena riceverai una richiesta la vedrai qui!' : 'Inizia subito a richiedere un video alle tue Star!'}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {requests.map(req => {
                        const resolvedTalentName = req.talentName || talents[req.talentId] || 'Star di CiaoStar';
                        const statusItalian = statusMap[req.status] || req.status;

                        return (
                            <div key={req.id} className={`bg-white rounded-3xl border p-8 shadow-sm transition-all hover:shadow-md ${
                                req.status === RequestStatus.PENDING && isTalent ? 'border-amber-200 ring-2 ring-amber-50' : 'border-gray-100'
                            }`}>
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                        req.status === RequestStatus.COMPLETED ? 'bg-emerald-100 text-emerald-600' :
                                        req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-600' :
                                        req.status === RequestStatus.ACCEPTED ? 'bg-blue-100 text-blue-600' :
                                        req.status === RequestStatus.REJECTED ? 'bg-red-100 text-red-600' :
                                        'bg-gray-100 text-slate-400'
                                    }`}>{statusItalian}</div>
                                    <span className="text-[10px] text-slate-300 font-bold uppercase">#ORD-{req.id.substring(0,6).toUpperCase()}</span>
                                </div>

                                <div className="flex justify-between items-end mb-6">
                                    <div>
                                        <h3 className="text-2xl font-extrabold text-slate-900 mb-1">
                                            {isTalent ? `Per: ${req.recipientName}` : `Da: ${resolvedTalentName}`}
                                        </h3>
                                        <p className="text-sm font-bold text-indigo-600 uppercase tracking-wider">{req.occasion}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">PREZZO</p>
                                        <p className="text-xl font-black text-slate-900">
                                            €{isTalent ? (req.pricePaid - (req.applicationFee || 0)).toFixed(2) : req.pricePaid.toFixed(2)}
                                        </p>
                                        {isTalent && (
                                            <div className="flex items-center gap-1 justify-end text-[9px] font-bold text-slate-400 uppercase mt-1">
                                                <ArrowDownRight className="w-2.5 h-2.5" />
                                                Lordo €{req.pricePaid.toFixed(2)}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="bg-gray-50 p-5 rounded-2xl mb-8 italic text-slate-600 text-sm leading-relaxed border-l-4 border-indigo-200 relative">
                                    <div className="absolute -top-3 left-4 bg-white px-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border border-gray-100 rounded">Istruzioni</div>
                                    "{req.instructions}"
                                </div>

                                {/* Azioni per la Star */}
                                {isTalent && (
                                    <div className="space-y-4">
                                        {req.status === RequestStatus.PENDING && (
                                            <div className="grid grid-cols-2 gap-3">
                                                <button 
                                                    onClick={() => setRejectingId(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl border-2 border-red-50 text-red-600 font-bold text-sm hover:bg-red-50 transition-all"
                                                >
                                                    <X className="w-4 h-4" /> Rifiuta
                                                </button>
                                                <button 
                                                    onClick={() => handleAccept(req.id)}
                                                    className="flex items-center justify-center gap-2 py-4 rounded-2xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                                >
                                                    <Check className="w-4 h-4" /> Accetta
                                                </button>
                                            </div>
                                        )}

                                        {req.status === RequestStatus.ACCEPTED && (
                                            <div>
                                                {uploadingId === req.id ? (
                                                    <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 space-y-6">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="font-black text-xs uppercase tracking-widest text-slate-900">Caricamento Video</h4>
                                                            <button onClick={() => setUploadingId(null)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>
                                                        </div>

                                                        <div className="space-y-4">
                                                            <label className="flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-200 rounded-2xl cursor-pointer hover:bg-white transition-all group">
                                                                <Upload className="w-8 h-8 text-slate-300 group-hover:text-indigo-600 mb-2 transition-colors" />
                                                                <span className="text-sm font-bold text-slate-500">
                                                                    {uploadFile ? uploadFile.name : 'Seleziona file video'}
                                                                </span>
                                                                <input type="file" className="hidden" accept="video/*" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
                                                            </label>

                                                            <div className="space-y-2 bg-white p-4 rounded-xl border border-gray-100">
                                                                <p className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
                                                                    <ShieldCheck className="w-3 h-3" /> Requisiti di Qualità
                                                                </p>
                                                                {[
                                                                    { key: 'nameSaid', label: 'Ho detto il nome del destinatario' },
                                                                    { key: 'durationOk', label: 'Il video dura almeno 20 secondi' },
                                                                    { key: 'audioClear', label: 'L\'audio è chiaro e senza rumori' }
                                                                ].map(item => (
                                                                    <label key={item.key} className="flex items-center gap-3 cursor-pointer group">
                                                                        <input 
                                                                            type="checkbox" 
                                                                            checked={(qualityCheck as any)[item.key]} 
                                                                            onChange={(e) => setQualityCheck({...qualityCheck, [item.key]: e.target.checked})}
                                                                            className="sr-only"
                                                                        />
                                                                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                                                            (qualityCheck as any)[item.key] ? 'bg-indigo-600 border-indigo-600' : 'border-gray-200 group-hover:border-indigo-300'
                                                                        }`}>
                                                                            {(qualityCheck as any)[item.key] && <Check className="w-3 h-3 text-white stroke-[3px]" />}
                                                                        </div>
                                                                        <span className="text-xs font-bold text-slate-600">{item.label}</span>
                                                                    </label>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        <button 
                                                            disabled={isUploading || !uploadFile}
                                                            onClick={() => handleUploadSubmit(req.id)}
                                                            className="btn-primary w-full py-4 text-sm disabled:opacity-50"
                                                        >
                                                            {isUploading ? (
                                                                <><Loader2 className="animate-spin w-4 h-4" /> Invio in corso...</>
                                                            ) : (
                                                                <><Video className="w-4 h-4" /> Consegna al Fan</>
                                                            )}
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button 
                                                        onClick={() => setUploadingId(req.id)}
