import React, { useEffect, useState } from 'react';
import { User, UserRole, VideoRequest, RequestStatus } from '../types';
import { getRequestsForUser, updateRequestStatus, uploadVideo, getTalents } from '../services/dataService';
import VideoPlayer from '../components/VideoPlayer';
import { 
  Loader2, CheckCircle, Package, Clock, RefreshCw,
  Download, Gift, PlayCircle, Check, X, Upload, Video, ShieldCheck, AlertCircle, TrendingUp, ArrowDownRight, MessageSquare, CornerUpLeft, Info
} from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [talents, setTalents] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);
  const [showDownloadHelp, setShowDownloadHelp] = useState(false);

  // Rejection States
  const [rejectingId, setRejectingId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);

  // Upload States
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [qualityCheck, setQualityCheck] = useState({
      nameSaid: false,
      durationOk: false,
      audioClear: false
  });

  const statusMap: Record<RequestStatus, string> = {
    [RequestStatus.PENDING]: 'In attesa',
    [RequestStatus.ACCEPTED]: 'Accettato',
    [RequestStatus.COMPLETED]: 'Consegnato',
    [RequestStatus.REJECTED]: 'Rifiutato',
    [RequestStatus.EXPIRED]: 'Scaduto',
    [RequestStatus.REFUNDED]: 'Rimborsato',
    [RequestStatus.CANCELED]: 'Annullato',
    [RequestStatus.CANCELED_BY_FAN]: 'Annullato da te',
    [RequestStatus.IN_REVIEW]: 'In revisione',
    [RequestStatus.DISPUTE_OPEN]: 'Disputa aperta',
    [RequestStatus.CORRECTION_NEEDED]: 'Correzione richiesta'
  };

  const refresh = async () => {
    setLoading(true);
    try {
        const [ordersData, talentsData] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getTalents()
        ]);

        const tMap: Record<string, string> = {};
        talentsData.forEach(t => { tMap[t.id] = t.name; });

        setTalents(tMap);
        setRequests(ordersData);
    } catch (err: any) {
        console.error(err);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { refresh(); }, [user.id, user.role]);

  const handleDownload = async (videoUrl: string, fileName: string, requestId: string) => {
    setDownloadingId(requestId);
    setShowDownloadHelp(false);

    try {
        // Tentativo di download forzato via Blob (richiede CORS su Firebase)
        const response = await fetch(videoUrl);
        if (!response.ok) throw new Error('CORS limit');

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${fileName.replace(/\s+/g, '_')}.mp4`;
        document.body.appendChild(link);
        link.click();

        // Cleanup
        setTimeout(() => {
            document.body.removeChild(link);
            window.URL.revokeObjectURL(url);
        }, 100);

    } catch (error) {
        console.warn('Download programmato fallito (CORS). Fallback al link con metadata.');
        // Piano B: Se il file è stato appena caricato con i nuovi metadati 'attachment',
        // navigare direttamente al link dovrebbe innescare il download del browser.

        const link = document.createElement('a');
        link.href = videoUrl;
        link.target = "_blank"; // Apriamo comunque in nuova scheda per sicurezza se non scarica
        link.setAttribute('download', `${fileName}.mp4`);
        link.click();

        // Mostriamo un piccolo aiuto visivo se il file viene solo aperto
        setShowDownloadHelp(true);
    } finally {
        setDownloadingId(null);
    }
  };

  const handleAccept = async (orderId: string) => {
      if (confirm("Accetti di realizzare questo video messaggio?")) {
          try {
              await updateRequestStatus(orderId, RequestStatus.ACCEPTED);
              refresh();
          } catch (e) {
              alert("Errore accettazione.");
          }
      }
  };

  const submitRejection = async () => {
      if (!rejectingId || !rejectionReason.trim()) return;

      setIsRejecting(true);
      try {
          await updateRequestStatus(rejectingId, RequestStatus.REJECTED, { rejectionReason });
          setRejectingId(null);
          setRejectionReason('');
          refresh();
      } catch (e) {
          alert("Errore rifiuto.");
      } finally {
          setIsRejecting(false);
      }
  };

  const handleUploadSubmit = async (orderId: string) => {
      if (!uploadFile) return;
      if (!qualityCheck.nameSaid || !qualityCheck.durationOk || !qualityCheck.audioClear) {
          alert("Per favore, conferma tutti i requisiti di qualità prima di caricare.");
          return;
      }

      setIsUploading(true);
      try {
          await uploadVideo(uploadFile, orderId, qualityCheck);
